import { useCallback, useState, type CSSProperties } from 'react';
import { Select, IconButton } from '../../primitives';
import { Save, Trash2 } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  FilterPresetSelector                                                      */
/*  Dropdown preset selector with save and delete actions.                    */
/*  Composes Select + IconButton + Input. Uses --ts-screener-* tokens.        */
/* -------------------------------------------------------------------------- */

export interface FilterPresetSelectorProps {
  /** Available filter presets. */
  presets: Array<{ id: string; name: string }>;
  /** Currently selected preset ID. Null when no preset matches. */
  selectedPresetId: string | null;
  /** Called when a preset is selected. */
  onPresetSelect: (presetId: string) => void;
  /** Called when the user saves the current filter configuration as a new preset. */
  onPresetSave: (name: string) => void;
  /** Called when a preset is deleted. */
  onPresetDelete: (presetId: string) => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-filter-preset-selector-styles';

function ensureFilterPresetSelectorStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-filter-preset-save-input]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-filter-preset-delete]:hover {
      color: var(--ts-text-danger, #ef4444);
    }
    [data-ts-filter-preset-delete]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureFilterPresetSelectorStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const saveRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  marginTop: 'var(--ts-space-2)',
};

const saveInputStyle: CSSProperties = {
  all: 'unset',
  flex: 1,
  height: 'var(--ts-input-height-sm)',
  padding: '0 var(--ts-input-padding-x)',
  background: 'var(--ts-input-bg)',
  color: 'var(--ts-input-text)',
  border: '1px solid var(--ts-input-border)',
  borderRadius: 'var(--ts-input-radius)',
  fontSize: 'var(--ts-input-font-size)',
  fontFamily: 'inherit',
  boxSizing: 'border-box',
};

const presetItemRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  gap: 'var(--ts-space-2)',
};

const SAVE_OPTION_VALUE = '__save_current__';

/* ----- Component --------------------------------------------------------- */

export function FilterPresetSelector({
  presets,
  selectedPresetId,
  onPresetSelect,
  onPresetSave,
  onPresetDelete,
}: FilterPresetSelectorProps): React.JSX.Element {
  const [showSaveInput, setShowSaveInput] = useState(false);
  const [saveName, setSaveName] = useState('');

  const options = [
    ...presets.map((p) => ({ value: p.id, label: p.name })),
    { value: SAVE_OPTION_VALUE, label: 'Save current...' },
  ];

  const handleValueChange = useCallback(
    (val: string) => {
      if (val === SAVE_OPTION_VALUE) {
        setShowSaveInput(true);
        return;
      }
      onPresetSelect(val);
    },
    [onPresetSelect],
  );

  const handleSave = useCallback(() => {
    const trimmed = saveName.trim();
    if (trimmed.length > 0) {
      onPresetSave(trimmed);
      setSaveName('');
      setShowSaveInput(false);
    }
  }, [saveName, onPresetSave]);

  const handleSaveKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        handleSave();
      }
      if (e.key === 'Escape') {
        setShowSaveInput(false);
        setSaveName('');
      }
    },
    [handleSave],
  );

  const handleDelete = useCallback(
    (e: React.MouseEvent, presetId: string) => {
      e.stopPropagation();
      e.preventDefault();
      onPresetDelete(presetId);
    },
    [onPresetDelete],
  );

  return (
    <div data-ts-filter-preset-selector="" style={containerStyle}>
      <Select
        options={options}
        value={selectedPresetId ?? undefined}
        onValueChange={handleValueChange}
        placeholder="Presets..."
        size="sm"
        label="Filter presets"
      />
      {presets.length > 0 && selectedPresetId !== null && (
        <div style={presetItemRowStyle}>
          <IconButton
            data-ts-filter-preset-delete=""
            icon={<Trash2 size={14} />}
            label="Delete preset"
            variant="ghost"
            size="sm"
            onClick={(e) => handleDelete(e, selectedPresetId)}
          />
        </div>
      )}
      {showSaveInput && (
        <div style={saveRowStyle}>
          <input
            data-ts-filter-preset-save-input=""
            type="text"
            value={saveName}
            onChange={(e) => setSaveName(e.target.value)}
            onKeyDown={handleSaveKeyDown}
            placeholder="Preset name..."
            style={saveInputStyle}
            aria-label="New preset name"
            autoFocus
          />
          <IconButton
            icon={<Save size={14} />}
            label="Save preset"
            variant="ghost"
            size="sm"
            onClick={handleSave}
          />
        </div>
      )}
    </div>
  );
}

FilterPresetSelector.displayName = 'FilterPresetSelector';
