import { useEffect, useRef, type CSSProperties } from 'react';

/* -------------------------------------------------------------------------- */
/*  SparklineChart                                                             */
/*  Canvas-rendered sparkline for watchlist inline price history.               */
/*  Uses --ts-sparkline-* tokens.                                              */
/* -------------------------------------------------------------------------- */

export interface SparklineChartProps {
  /** Array of price values forming the sparkline. Minimum 2 points. */
  data: number[];
  /** Width in CSS pixels. Default 80. */
  width?: number;
  /** Height in CSS pixels. Default 24. */
  height?: number;
  /** Whether to fill the area under the line. Default true. */
  showFill?: boolean;
  /** Direction override. If omitted, derived from first vs last data point. */
  direction?: 'up' | 'down' | 'neutral';
  /** Additional class name. */
  className?: string;
}

/* ----- Helpers ----------------------------------------------------------- */

function resolveDirection(
  data: number[],
  override?: 'up' | 'down' | 'neutral',
): 'up' | 'down' | 'neutral' {
  if (override !== undefined) return override;
  const first = data[0];
  const last = data[data.length - 1];
  if (first === undefined || last === undefined) return 'neutral';
  if (last > first) return 'up';
  if (last < first) return 'down';
  return 'neutral';
}

const DIRECTION_TOKEN: Record<'up' | 'down' | 'neutral', string> = {
  up: '--ts-sparkline-up-stroke',
  down: '--ts-sparkline-down-stroke',
  neutral: '--ts-sparkline-neutral-stroke',
};

function getCSSVar(el: Element, name: string): string {
  return getComputedStyle(el).getPropertyValue(name).trim();
}

/* ----- Component --------------------------------------------------------- */

export function SparklineChart({
  data,
  width = 80,
  height = 24,
  showFill = true,
  direction: directionOverride,
  className,
}: SparklineChartProps): React.JSX.Element | null {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    if (data.length < 2) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = typeof window !== 'undefined' ? window.devicePixelRatio : 1;
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    ctx.scale(dpr, dpr);

    const dir = resolveDirection(data, directionOverride);
    const strokeColor = getCSSVar(canvas, DIRECTION_TOKEN[dir]) || '#888';
    const fillOpacity = getCSSVar(canvas, '--ts-sparkline-fill-opacity') || '0.1';
    const strokeWidth = parseFloat(getCSSVar(canvas, '--ts-sparkline-stroke-width') || '1.5');

    const min = Math.min(...data);
    const max = Math.max(...data);
    const range = max - min || 1;
    const padding = 1;
    const drawWidth = width - padding * 2;
    const drawHeight = height - padding * 2;

    const points: Array<{ x: number; y: number }> = data.map((value, i) => ({
      x: padding + (i / (data.length - 1)) * drawWidth,
      y: padding + drawHeight - ((value - min) / range) * drawHeight,
    }));

    ctx.clearRect(0, 0, width, height);

    const firstPoint = points[0];
    const lastPoint = points[points.length - 1];
    if (!firstPoint || !lastPoint) return;

    /* Draw fill */
    if (showFill) {
      ctx.beginPath();
      ctx.moveTo(firstPoint.x, firstPoint.y);
      for (let i = 1; i < points.length; i++) {
        const pt = points[i];
        if (pt) ctx.lineTo(pt.x, pt.y);
      }
      ctx.lineTo(lastPoint.x, height);
      ctx.lineTo(firstPoint.x, height);
      ctx.closePath();
      ctx.globalAlpha = parseFloat(fillOpacity);
      ctx.fillStyle = strokeColor;
      ctx.fill();
      ctx.globalAlpha = 1;
    }

    /* Draw line */
    ctx.beginPath();
    ctx.moveTo(firstPoint.x, firstPoint.y);
    for (let i = 1; i < points.length; i++) {
      const pt = points[i];
      if (pt) ctx.lineTo(pt.x, pt.y);
    }
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = strokeWidth;
    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';
    ctx.stroke();
  }, [data, width, height, showFill, directionOverride]);

  const canvasStyle: CSSProperties = {
    width: `${width}px`,
    height: `${height}px`,
    display: 'block',
  };

  if (data.length < 2) return null;

  return (
    <canvas
      ref={canvasRef}
      data-ts-sparkline=""
      className={className}
      style={canvasStyle}
      data-testid="sparkline-chart"
    />
  );
}

SparklineChart.displayName = 'SparklineChart';
