import { useMemo, type CSSProperties } from 'react';
import { VirtualList, Badge } from '../primitives';
import { TradeRow, type TradeSide } from './TradeRow';
import { TradeHistoryControls } from './TradeHistoryControls';

/* -------------------------------------------------------------------------- */
/*  TradeHistoryPanel                                                          */
/*  Virtualized trade history (time & sales) with filters and streaming.       */
/*  Uses --ts-trade-* tokens. Composes TradeRow, TradeHistoryControls.         */
/* -------------------------------------------------------------------------- */

export interface Trade {
  /** Unique trade identifier. */
  id: string;
  /** Trade timestamp (ISO string or epoch ms). */
  time: string;
  /** Trade price. */
  price: number;
  /** Trade size. */
  size: number;
  /** Trade side. */
  side: TradeSide;
  /** Whether this is a significant trade. */
  significant?: boolean;
}

export interface TradeHistoryPanelProps {
  /** Instrument symbol. */
  symbol: string;
  /** Array of trades, newest first. */
  trades: Trade[];
  /** Number of new trades since the user scrolled away from top. */
  newTradeCount: number;
  /** Called when the user clicks the "new trades" badge to scroll to top. */
  onScrollToTop: () => void;
  /** Price precision. */
  precision?: number;
  /** Size precision. */
  sizePrecision?: number;
  /** Minimum trade size filter. */
  sizeFilter: number;
  /** Called when size filter changes. */
  onSizeFilterChange: (size: number) => void;
  /** Side filter. */
  sideFilter: TradeSide | null;
  /** Called when side filter changes. */
  onSideFilterChange: (side: TradeSide | null) => void;
  /** Whether the feed is paused. */
  paused: boolean;
  /** Called when pause state changes. */
  onPausedChange: (paused: boolean) => void;
  /** Called when a trade row is clicked. */
  onTradeClick?: (trade: Trade) => void;
  /** Display density mode. */
  densityMode: 'compact' | 'expanded';
}

/* ----- Style injection --------------------------------------------------- */

const TRADE_PANEL_STYLE_ID = 'ts-trade-history-panel-styles';

function ensureTradeHistoryPanelStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(TRADE_PANEL_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = TRADE_PANEL_STYLE_ID;
  sheet.textContent = `
    [data-ts-new-trades-badge]:hover {
      filter: brightness(1.1);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTradeHistoryPanelStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  background: 'var(--ts-panel-bg)',
  border: '1px solid var(--ts-panel-border)',
  borderRadius: 'var(--ts-radius-sm)',
  overflow: 'hidden',
};

const headerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-panel-header-height)',
  padding: '0 var(--ts-panel-header-padding-x)',
  background: 'var(--ts-panel-header-bg)',
  color: 'var(--ts-panel-header-text)',
  fontSize: 'var(--ts-font-md)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  borderBottom: '1px solid var(--ts-panel-border)',
  gap: 'var(--ts-space-2)',
  userSelect: 'none',
  flexShrink: 0,
};

const columnHeaderRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-ob-column-header-height)',
  background: 'var(--ts-ob-column-header-bg)',
  color: 'var(--ts-ob-column-header-text)',
  fontSize: 'var(--ts-ob-column-header-font-size)',
  padding: '0 var(--ts-space-2)',
  textTransform: 'uppercase',
  userSelect: 'none',
  flexShrink: 0,
};

const colCellStyle: CSSProperties = {
  flex: 1,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const bodyStyle: CSSProperties = {
  flex: '1 1 0',
  position: 'relative',
  overflow: 'hidden',
};

const badgeContainerStyle: CSSProperties = {
  position: 'absolute',
  top: 'var(--ts-space-1)',
  left: '50%',
  transform: 'translateX(-50%)',
  zIndex: 10,
  cursor: 'pointer',
};

const badgeStyle: CSSProperties = {
  background: 'var(--ts-trade-new-badge-bg)',
  color: 'var(--ts-trade-new-badge-text)',
  fontSize: 'var(--ts-font-xs)',
  padding: '2px var(--ts-space-2)',
  borderRadius: 'var(--ts-radius-sm)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  whiteSpace: 'nowrap',
  userSelect: 'none',
  boxShadow: 'var(--ts-shadow-sm)',
};

const emptyStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: '100%',
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-sm)',
  userSelect: 'none',
};

const pausedIndicatorStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-status-warning)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
};

/* ----- Component --------------------------------------------------------- */

export function TradeHistoryPanel({
  symbol,
  trades,
  newTradeCount,
  onScrollToTop,
  precision = 2,
  sizePrecision = 4,
  sizeFilter,
  onSizeFilterChange,
  sideFilter,
  onSideFilterChange,
  paused,
  onPausedChange,
  onTradeClick,
  densityMode,
}: TradeHistoryPanelProps): React.JSX.Element {
  const filteredTrades = useMemo(() => {
    let result = trades;
    if (sizeFilter > 0) {
      result = result.filter((t) => t.size >= sizeFilter);
    }
    if (sideFilter !== null) {
      result = result.filter((t) => t.side === sideFilter);
    }
    return result;
  }, [trades, sizeFilter, sideFilter]);

  const itemHeight = densityMode === 'compact' ? 22 : 28;

  return (
    <div
      data-ts-trade-history-panel=""
      data-density={densityMode}
      style={rootStyle}
      data-testid="trade-history-panel"
    >
      <div style={headerStyle}>
        <span style={{ flex: 1 }}>Time &amp; Sales</span>
        {paused && (
          <span style={pausedIndicatorStyle} data-testid="trade-paused-indicator">
            Paused
          </span>
        )}
      </div>

      <TradeHistoryControls
        sizeFilter={sizeFilter}
        onSizeFilterChange={onSizeFilterChange}
        sideFilter={sideFilter}
        onSideFilterChange={onSideFilterChange}
        paused={paused}
        onPausedChange={onPausedChange}
        tradeCount={trades.length}
      />

      <div style={columnHeaderRowStyle} data-testid="trade-column-headers">
        <span style={colCellStyle}>Time</span>
        <span style={{ ...colCellStyle, textAlign: 'right' }}>Price</span>
        <span style={{ ...colCellStyle, textAlign: 'right' }}>Size</span>
      </div>

      <div style={bodyStyle}>
        {newTradeCount > 0 && (
          <div
            data-ts-new-trades-badge=""
            style={badgeContainerStyle}
            onClick={onScrollToTop}
            role="button"
            tabIndex={0}
            onKeyDown={(e) => {
              if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                onScrollToTop();
              }
            }}
            aria-label={`${newTradeCount} new trades, click to scroll to top`}
            data-testid="new-trades-badge"
          >
            <span style={badgeStyle}>
              {newTradeCount} new trade{newTradeCount !== 1 ? 's' : ''}
            </span>
          </div>
        )}

        {filteredTrades.length === 0 ? (
          <div style={emptyStyle} data-testid="trade-empty-state">
            No trades
          </div>
        ) : (
          <VirtualList
            items={filteredTrades}
            itemHeight={itemHeight}
            overscan={5}
            renderItem={(trade) => (
              <TradeRow
                time={trade.time}
                price={trade.price}
                size={trade.size}
                side={trade.side}
                precision={precision}
                sizePrecision={sizePrecision}
                significant={trade.significant}
                onClick={onTradeClick ? () => onTradeClick(trade) : undefined}
              />
            )}
          />
        )}
      </div>
    </div>
  );
}

TradeHistoryPanel.displayName = 'TradeHistoryPanel';
