import {
  forwardRef,
  useCallback,
  type CSSProperties,
  type ReactNode,
  type KeyboardEvent,
} from 'react';
import { Skeleton } from '../../primitives';
import { PriceChange, formatCompactNumber } from '../../financial';

/* -------------------------------------------------------------------------- */
/*  MetricCard                                                                */
/*  Displays a single metric with label, value, change, and optional          */
/*  sparkline. Uses --ts-metric-card-* tokens.                                */
/* -------------------------------------------------------------------------- */

export interface MetricCardProps {
  /** Metric label (e.g., "24h Volume", "Open Interest"). */
  label: string;
  /** Primary metric value (raw number). */
  value: number;
  /** Previous value for change calculation. Omit to hide change indicator. */
  previousValue?: number;
  /** Change percentage. If provided, overrides calculated change from value/previousValue. */
  changePercent?: number;
  /** Unit label displayed next to the value (e.g., "USD", "BTC"). */
  unit?: string;
  /** Icon element rendered at top-left. */
  icon?: ReactNode;
  /** Mini sparkline data for trend visualization. */
  sparklineData?: number[];
  /** Number formatting precision. */
  precision?: number;
  /** Called when the card is clicked (navigates to detail view). */
  onClick?: () => void;
  /** Whether this card is in a loading state. */
  loading?: boolean;
  /** Size variant. Compact for pane mode, default for window mode. */
  size?: 'compact' | 'default';
}

/* ----- Style injection for hover/focus states ----------------------------- */

const METRIC_CARD_STYLE_ID = 'ts-metric-card-styles';

function ensureMetricCardStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(METRIC_CARD_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = METRIC_CARD_STYLE_ID;
  sheet.textContent = `
    [data-ts-metric-card][data-clickable]:hover {
      background: var(--ts-surface-2);
    }
    [data-ts-metric-card][data-clickable]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureMetricCardStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  background: 'var(--ts-metric-card-bg)',
  border: '1px solid var(--ts-metric-card-border)',
  borderRadius: 'var(--ts-metric-card-radius)',
  padding: 'var(--ts-metric-card-padding)',
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-2)',
  transition: 'background 150ms',
};

const compactRootStyle: CSSProperties = {
  ...rootStyle,
  padding: 'var(--ts-space-2)',
  gap: 'var(--ts-space-1)',
};

const labelRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const iconStyle: CSSProperties = {
  color: 'var(--ts-metric-card-icon-color)',
  display: 'flex',
  alignItems: 'center',
  flexShrink: 0,
};

const labelStyle: CSSProperties = {
  color: 'var(--ts-metric-card-label-text)',
  fontSize: 'var(--ts-metric-card-label-font-size)',
  fontWeight: 'var(--ts-metric-card-label-font-weight)' as unknown as number,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const valueStyle: CSSProperties = {
  color: 'var(--ts-metric-card-value-text)',
  fontSize: 'var(--ts-metric-card-value-font-size)',
  fontWeight: 'var(--ts-metric-card-value-font-weight)' as unknown as number,
  fontFamily: 'var(--ts-metric-card-value-font)',
  fontVariantNumeric: 'tabular-nums slashed-zero',
  fontFeatureSettings: "'tnum' 1, 'zero' 1",
  lineHeight: 1.2,
};

const compactValueStyle: CSSProperties = {
  ...valueStyle,
  fontSize: 'var(--ts-font-lg)',
};

const unitStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 'var(--ts-font-weight-normal)' as unknown as number,
  marginLeft: 'var(--ts-space-1)',
};

const sparklineContainerStyle: CSSProperties = {
  width: '100%',
  height: 40,
  opacity: 0.7,
};

export const MetricCard = forwardRef<HTMLDivElement, MetricCardProps>(
  function MetricCard(
    {
      label,
      value,
      previousValue,
      changePercent,
      unit,
      icon,
      sparklineData,
      precision = 2,
      onClick,
      loading = false,
      size = 'default',
    },
    ref,
  ) {
    const isCompact = size === 'compact';
    const isClickable = onClick !== undefined;

    const resolvedChangePercent =
      changePercent !== undefined
        ? changePercent
        : previousValue !== undefined && previousValue !== 0
          ? ((value - previousValue) / Math.abs(previousValue)) * 100
          : undefined;

    const changeAbsolute =
      previousValue !== undefined ? value - previousValue : 0;

    const handleKeyDown = useCallback(
      (e: KeyboardEvent<HTMLDivElement>) => {
        if (isClickable && (e.key === 'Enter' || e.key === ' ')) {
          e.preventDefault();
          onClick?.();
        }
      },
      [isClickable, onClick],
    );

    const interactiveProps = isClickable
      ? {
          role: 'button' as const,
          tabIndex: 0,
          onClick,
          onKeyDown: handleKeyDown,
          style: {
            ...(isCompact ? compactRootStyle : rootStyle),
            cursor: 'pointer',
          },
        }
      : {
          style: isCompact ? compactRootStyle : rootStyle,
        };

    if (loading) {
      return (
        <div
          ref={ref}
          data-ts-metric-card=""
          {...interactiveProps}
        >
          <div style={labelRowStyle}>
            <Skeleton width={80} height={14} />
          </div>
          <Skeleton width={120} height={24} />
          <Skeleton width={60} height={16} />
        </div>
      );
    }

    return (
      <div
        ref={ref}
        data-ts-metric-card=""
        data-clickable={isClickable ? '' : undefined}
        {...interactiveProps}
      >
        {/* Row 1: Icon + Label */}
        <div style={labelRowStyle}>
          {icon !== undefined && (
            <span style={iconStyle} aria-hidden>
              {icon}
            </span>
          )}
          <span style={labelStyle}>{label}</span>
        </div>

        {/* Row 2: Primary value */}
        <div style={isCompact ? compactValueStyle : valueStyle}>
          {formatCompactNumber(value, precision)}
          {unit !== undefined && <span style={unitStyle}>{unit}</span>}
        </div>

        {/* Row 3: Change indicator */}
        {resolvedChangePercent !== undefined && (
          <PriceChange
            value={changeAbsolute}
            percentage={resolvedChangePercent}
            showAbsolute={false}
            showPercentage
            size="sm"
          />
        )}

        {/* Row 4: Sparkline (hidden in compact mode) */}
        {!isCompact && sparklineData !== undefined && sparklineData.length > 1 && (
          <div style={sparklineContainerStyle} aria-hidden>
            {/* SparklineChart placeholder - rendered by parent when available */}
          </div>
        )}
      </div>
    );
  },
);

MetricCard.displayName = 'MetricCard';
