import { forwardRef, type CSSProperties } from 'react';
import { SymbolChip, PriceDisplay, PriceChange } from '../financial';
import { IconButton, Tooltip } from '../primitives';
import { Plus } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  SymbolDisplay                                                             */
/*  Symbol chip + price + change display for the chart top bar.               */
/*  Uses --ts-symbol-chip-* and --ts-price-* tokens.                          */
/* -------------------------------------------------------------------------- */

export interface SymbolDisplayProps {
  /** Ticker symbol, e.g. "BTCUSDT". */
  symbol: string;
  /** Exchange name, e.g. "Binance". */
  exchange?: string;
  /** Current price. */
  price?: number;
  /** Absolute price change. */
  priceChange?: number;
  /** Percentage price change. */
  priceChangePercent?: number;
  /** Decimal places for price display. */
  precision?: number;
  /** Called when the symbol button is clicked (opens symbol search). */
  onSymbolClick?: () => void;
  /** Called when the compare button is clicked. */
  onCompareClick?: () => void;
  /** Whether to show price and change info. Default true. */
  showPrice?: boolean;
  /** Whether to show the compare (+) button. Default true. */
  showCompare?: boolean;
  /** Whether to use compact layout (pane mode). */
  compact?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-symbol-display-styles';

function ensureSymbolDisplayStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-symbol-display] {
      display: inline-flex;
      align-items: center;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureSymbolDisplayStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '8px',
  flexShrink: 0,
};

/* ----- Component --------------------------------------------------------- */

export const SymbolDisplay = forwardRef<HTMLDivElement, SymbolDisplayProps>(
  function SymbolDisplay(
    {
      symbol,
      exchange,
      price,
      priceChange,
      priceChangePercent,
      precision = 2,
      onSymbolClick,
      onCompareClick,
      showPrice = true,
      showCompare = true,
      compact = false,
    },
    ref,
  ) {
    return (
      <div ref={ref} data-ts-symbol-display="" style={containerStyle}>
        <SymbolChip
          symbol={symbol}
          exchange={exchange}
          onClick={onSymbolClick}
        />

        {showPrice && price !== undefined && (
          <PriceDisplay
            value={price}
            precision={precision}
          />
        )}

        {showPrice && !compact && priceChange !== undefined && priceChangePercent !== undefined && (
          <PriceChange
            value={priceChange}
            percentage={priceChangePercent}
            size="sm"
          />
        )}

        {showCompare && !compact && onCompareClick !== undefined && (
          <Tooltip content="Compare or Add Symbol" shortcut="+" side="bottom">
            <IconButton
              icon={<Plus size={16} />}
              label="Compare or Add Symbol"
              variant="ghost"
              size="sm"
              onClick={onCompareClick}
            />
          </Tooltip>
        )}
      </div>
    );
  },
);

SymbolDisplay.displayName = 'SymbolDisplay';
