import {
  Component,
  type ReactNode,
  type ErrorInfo,
  type CSSProperties,
  type ComponentType,
} from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ErrorBoundary                                                              */
/*  Three-level error boundary: component (inline), panel (retryable),        */
/*  app (full page). Uses --ts-* CSS custom properties.                       */
/* -------------------------------------------------------------------------- */

/* ----- Types -------------------------------------------------------------- */

export type ErrorBoundaryLevel = 'component' | 'panel' | 'app';

export interface ErrorBoundaryProps {
  /** Boundary level: component (inline), panel (retryable), app (full page) */
  level: ErrorBoundaryLevel;
  /** Fallback to render on error */
  fallback?: ReactNode;
  /** Called when error is caught */
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
  /** Children to wrap */
  children: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
  retryKey: number;
}

/* ----- Style injection --------------------------------------------------- */

const ERROR_BOUNDARY_STYLE_ID = 'ts-error-boundary-styles';

function ensureErrorBoundaryStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(ERROR_BOUNDARY_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = ERROR_BOUNDARY_STYLE_ID;
  sheet.textContent = `
    [data-ts-error-boundary-retry]:hover {
      background: var(--ts-accent-hover, rgba(59, 130, 246, 0.2));
      border-color: var(--ts-accent-default, #3b82f6);
    }
    [data-ts-error-boundary-retry]:focus-visible {
      outline: 2px solid var(--ts-accent-default, #3b82f6);
      outline-offset: 2px;
    }
    [data-ts-error-boundary-reload]:hover {
      background: var(--ts-accent-hover, rgba(59, 130, 246, 0.2));
      border-color: var(--ts-accent-default, #3b82f6);
    }
    [data-ts-error-boundary-reload]:focus-visible {
      outline: 2px solid var(--ts-accent-default, #3b82f6);
      outline-offset: 2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureErrorBoundaryStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const componentFallbackStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1, 4px)',
  fontSize: 'var(--ts-font-xs, 11px)',
  color: 'var(--ts-text-tertiary, #888)',
  padding: '4px 8px',
  fontFamily: 'inherit',
};

const panelFallbackStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  gap: 'var(--ts-space-3, 12px)',
  padding: 'var(--ts-space-6, 24px)',
  height: '100%',
  minHeight: 120,
  textAlign: 'center',
  fontFamily: 'inherit',
};

const panelIconStyle: CSSProperties = {
  color: 'var(--ts-status-warning, #f59e0b)',
  display: 'flex',
  alignItems: 'center',
};

const panelMessageStyle: CSSProperties = {
  fontSize: 'var(--ts-font-md, 14px)',
  color: 'var(--ts-text-secondary)',
  margin: 0,
  maxWidth: 320,
  lineHeight: 1.5,
};

const retryButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1, 4px)',
  fontSize: 'var(--ts-font-sm, 12px)',
  fontFamily: 'inherit',
  color: 'var(--ts-accent-default, #3b82f6)',
  padding: '6px 14px',
  borderRadius: 'var(--ts-radius-md, 8px)',
  border: '1px solid var(--ts-panel-border, #333)',
  cursor: 'pointer',
  transition: 'background 100ms, border-color 100ms',
  boxSizing: 'border-box',
};

const appFallbackStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  gap: 'var(--ts-space-4, 16px)',
  padding: 'var(--ts-space-8, 32px)',
  height: '100%',
  width: '100%',
  textAlign: 'center',
  fontFamily: 'inherit',
  background: 'var(--ts-panel-bg, #1e1e2e)',
  color: 'var(--ts-text-primary)',
  boxSizing: 'border-box',
};

const appTitleStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xl, 20px)',
  fontWeight: 600,
  color: 'var(--ts-text-primary)',
  margin: 0,
};

const appMessageStyle: CSSProperties = {
  fontSize: 'var(--ts-font-md, 14px)',
  color: 'var(--ts-text-secondary)',
  margin: 0,
  maxWidth: 420,
  lineHeight: 1.5,
};

const appErrorDetailStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs, 11px)',
  color: 'var(--ts-text-tertiary, #888)',
  fontFamily: 'monospace',
  background: 'var(--ts-surface-2, rgba(255,255,255,0.04))',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  padding: '8px 12px',
  maxWidth: 480,
  overflow: 'auto',
  maxHeight: 120,
  whiteSpace: 'pre-wrap',
  wordBreak: 'break-word',
  textAlign: 'left',
};

const reloadButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2, 8px)',
  fontSize: 'var(--ts-font-md, 14px)',
  fontFamily: 'inherit',
  color: 'var(--ts-accent-default, #3b82f6)',
  padding: '10px 20px',
  borderRadius: 'var(--ts-radius-md, 8px)',
  border: '1px solid var(--ts-panel-border, #333)',
  cursor: 'pointer',
  transition: 'background 100ms, border-color 100ms',
  boxSizing: 'border-box',
};

/* ----- Default fallback renderers ---------------------------------------- */

function ComponentFallback(): React.JSX.Element {
  return (
    <span data-ts-error-boundary-fallback="" data-level="component" style={componentFallbackStyle} role="alert">
      <AlertTriangle size={12} aria-hidden />
      Something went wrong
    </span>
  );
}

function PanelFallback({ onRetry }: { onRetry: () => void }): React.JSX.Element {
  return (
    <div data-ts-error-boundary-fallback="" data-level="panel" style={panelFallbackStyle} role="alert">
      <span style={panelIconStyle} aria-hidden>
        <AlertTriangle size={24} />
      </span>
      <p style={panelMessageStyle}>
        This panel encountered an error and could not render.
      </p>
      <button
        data-ts-error-boundary-retry=""
        type="button"
        style={retryButtonStyle}
        onClick={onRetry}
      >
        <RefreshCw size={14} aria-hidden />
        Retry
      </button>
    </div>
  );
}

function AppFallback({ error }: { error: Error | null }): React.JSX.Element {
  const handleReload = (): void => {
    if (typeof window !== 'undefined') {
      window.location.reload();
    }
  };

  return (
    <div data-ts-error-boundary-fallback="" data-level="app" style={appFallbackStyle} role="alert">
      <span style={panelIconStyle} aria-hidden>
        <AlertTriangle size={40} />
      </span>
      <h1 style={appTitleStyle}>Application Error</h1>
      <p style={appMessageStyle}>
        Deskmodal encountered an unexpected error and needs to reload.
      </p>
      {error !== null && (
        <pre style={appErrorDetailStyle}>
          {error.message}
        </pre>
      )}
      <button
        data-ts-error-boundary-reload=""
        type="button"
        style={reloadButtonStyle}
        onClick={handleReload}
      >
        <RefreshCw size={16} aria-hidden />
        Reload Application
      </button>
    </div>
  );
}

/* ----- ErrorBoundary class component ------------------------------------- */

export class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  static displayName = 'ErrorBoundary';

  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null, retryKey: 0 };
  }

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
    this.props.onError?.(error, errorInfo);
  }

  componentDidUpdate(prevProps: ErrorBoundaryProps): void {
    // component level: auto-retry when children change
    if (
      this.props.level === 'component' &&
      this.state.hasError &&
      prevProps.children !== this.props.children
    ) {
      this.setState({ hasError: false, error: null });
    }
  }

  private handleRetry = (): void => {
    this.setState((prev) => ({
      hasError: false,
      error: null,
      retryKey: prev.retryKey + 1,
    }));
  };

  render(): ReactNode {
    const { level, fallback, children } = this.props;
    const { hasError, error, retryKey } = this.state;

    if (!hasError) {
      // Use key to force re-mount on retry for panel/app levels
      if (level === 'panel' || level === 'app') {
        return <ErrorBoundaryKeyedWrapper key={retryKey}>{children}</ErrorBoundaryKeyedWrapper>;
      }
      return children;
    }

    // Custom fallback takes precedence
    if (fallback !== undefined) {
      return fallback;
    }

    switch (level) {
      case 'component':
        return <ComponentFallback />;
      case 'panel':
        return <PanelFallback onRetry={this.handleRetry} />;
      case 'app':
        return <AppFallback error={error} />;
    }
  }
}

/**
 * Simple wrapper that renders children. Used to force re-mount via key prop.
 */
function ErrorBoundaryKeyedWrapper({ children }: { children: ReactNode }): React.JSX.Element {
  return <>{children}</>;
}

/* ----- HOC --------------------------------------------------------------- */

/**
 * Higher-order component that wraps a component in an ErrorBoundary.
 */
export function withErrorBoundary<P extends Record<string, unknown>>(
  WrappedComponent: ComponentType<P>,
  level: ErrorBoundaryLevel,
): ComponentType<P> {
  function WithErrorBoundary(props: P): React.JSX.Element {
    return (
      <ErrorBoundary level={level}>
        <WrappedComponent {...props} />
      </ErrorBoundary>
    );
  }
  WithErrorBoundary.displayName = `withErrorBoundary(${WrappedComponent.displayName ?? WrappedComponent.name ?? 'Component'})`;
  return WithErrorBoundary;
}
