import { create } from 'zustand';
import type { AggregatedOrderbook, AggregatedLevel } from '@deskmodal/data-layer';

/** A single level for the UI orderbook display. */
export interface DepthOrderbookLevel {
  readonly price: number;
  readonly size: number;
  readonly total: number;
}

export interface DepthStore {
  /** Active symbol (e.g., "BTC/USDT"). */
  symbol: string;
  /** Bid levels with cumulative totals, sorted price descending. */
  bids: DepthOrderbookLevel[];
  /** Ask levels with cumulative totals, sorted price ascending. */
  asks: DepthOrderbookLevel[];
  /** Spread between best ask and best bid (null = no data yet). */
  spread: number | null;
  /** Mid price = (bestBid + bestAsk) / 2 (null = no data yet). */
  midPrice: number | null;
  /** Order imbalance = (bidVolume - askVolume) / (bidVolume + askVolume). */
  imbalance: number;
  /** Timestamp of the last orderbook update. */
  lastUpdate: number;

  /** Replace the entire orderbook from an aggregated snapshot. */
  setOrderbook(book: AggregatedOrderbook): void;
  /** Switch to a new symbol, resetting all book data. */
  setSymbol(symbol: string): void;
}

function aggregatedLevelsToUI(
  levels: ReadonlyArray<AggregatedLevel>,
): DepthOrderbookLevel[] {
  let cumulative = 0;
  return levels.map((l) => {
    cumulative += l.quantity;
    return { price: l.price, size: l.quantity, total: cumulative };
  });
}

function computeTotalVolume(levels: ReadonlyArray<AggregatedLevel>): number {
  let total = 0;
  for (const level of levels) {
    total += level.quantity;
  }
  return total;
}

/**
 * Compare UI orderbook levels against incoming aggregated levels.
 * Returns true if they represent identical price/quantity data,
 * allowing us to skip redundant state updates that cause re-renders.
 */
function levelsEqual(a: readonly DepthOrderbookLevel[], b: ReadonlyArray<AggregatedLevel>): boolean {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) {
    const aLevel = a[i];
    const bLevel = b[i];
    if (!aLevel || !bLevel) return false;
    if (aLevel.price !== bLevel.price || aLevel.size !== bLevel.quantity) return false;
  }
  return true;
}

export const useDepthStore = create<DepthStore>((set, get) => ({
  symbol: '',
  bids: [],
  asks: [],
  spread: null,
  midPrice: null,
  imbalance: 0,
  lastUpdate: 0,

  setOrderbook(book: AggregatedOrderbook) {
    const state = get();

    // Skip update if bids and asks are identical — prevents unnecessary re-renders
    if (levelsEqual(state.bids, book.bids) && levelsEqual(state.asks, book.asks)) return;

    const uiBids = aggregatedLevelsToUI(book.bids);
    const uiAsks = aggregatedLevelsToUI(book.asks);

    const bestBid = book.bids[0]?.price ?? null;
    const bestAsk = book.asks[0]?.price ?? null;

    const spread = bestAsk != null && bestBid != null ? bestAsk - bestBid : null;
    const midPrice = bestAsk != null && bestBid != null ? (bestBid + bestAsk) / 2 : null;

    const bidVolume = computeTotalVolume(book.bids);
    const askVolume = computeTotalVolume(book.asks);
    const totalVolume = bidVolume + askVolume;
    const imbalance = totalVolume > 0 ? (bidVolume - askVolume) / totalVolume : 0;

    set({
      symbol: book.symbol,
      bids: uiBids,
      asks: uiAsks,
      spread,
      midPrice,
      imbalance,
      lastUpdate: book.timestamp,
    });
  },

  setSymbol(symbol: string) {
    // Only update the symbol string. Keep existing orderbook data visible
    // until replaced by new data for the new symbol. This prevents the
    // "Awaiting data" flash when switching instruments.
    set({ symbol });
  },
}));
