import { forwardRef, type CSSProperties } from 'react';
import { Select as SelectPrimitive } from 'radix-ui';
import { ChevronDown, Check } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  Select                                                                    */
/*  Dropdown select with keyboard navigation.                                 */
/*  Wraps Radix Select — uses --ts-select-* tokens.                           */
/* -------------------------------------------------------------------------- */

type SelectSize = 'sm' | 'md' | 'lg';

interface SelectOption {
  value: string;
  label: string;
}

export interface SelectProps {
  /** Available options. */
  options: SelectOption[];
  /** Current selected value. */
  value?: string;
  /** Called when selection changes. */
  onValueChange?: (value: string) => void;
  /** Placeholder text when no value is selected. */
  placeholder?: string;
  /** Whether the select is disabled. */
  disabled?: boolean;
  /** Select size controlling trigger height. */
  size?: SelectSize;
  /** Accessible label for the select. */
  label?: string;
}

/* ----- Style injection for hover/focus states ---------------------------- */

const SELECT_STYLE_ID = 'ts-select-styles';

function ensureSelectStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(SELECT_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = SELECT_STYLE_ID;
  sheet.textContent = `
    [data-ts-select-trigger]:not(:disabled):hover {
      border-color: var(--ts-select-trigger-border-hover);
    }
    [data-ts-select-trigger]:focus-visible {
      border-color: var(--ts-select-trigger-border-focus);
      outline: 1px solid var(--ts-select-trigger-border-focus);
      outline-offset: -1px;
    }
    [data-ts-select-trigger]:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
    [data-ts-select-item]:hover,
    [data-ts-select-item][data-highlighted] {
      background: var(--ts-select-item-bg-hover);
      outline: none;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureSelectStyles();
}

/* ----- Size styles ------------------------------------------------------- */

const SIZE_HEIGHTS: Record<SelectSize, string> = {
  sm: 'var(--ts-input-height-sm)',
  md: 'var(--ts-input-height-md)',
  lg: 'var(--ts-input-height-lg)',
};

const triggerStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  gap: 'var(--ts-space-2)',
  background: 'var(--ts-select-trigger-bg)',
  color: 'var(--ts-select-trigger-text)',
  border: '1px solid var(--ts-select-trigger-border)',
  borderRadius: 'var(--ts-input-radius)',
  padding: '0 var(--ts-input-padding-x)',
  fontSize: 'var(--ts-input-font-size)',
  fontFamily: 'inherit',
  cursor: 'pointer',
  boxSizing: 'border-box',
  transition: 'border-color 150ms',
  minWidth: 120,
};

const chevronStyle: CSSProperties = {
  color: 'var(--ts-select-trigger-chevron)',
  flexShrink: 0,
};

const contentStyle: CSSProperties = {
  background: 'var(--ts-select-content-bg)',
  border: '1px solid var(--ts-select-content-border)',
  borderRadius: 'var(--ts-input-radius)',
  boxShadow: 'var(--ts-select-content-shadow)',
  overflow: 'hidden',
  padding: 'var(--ts-space-1) 0',
  zIndex: 50,
};

const viewportStyle: CSSProperties = {
  padding: 0,
};

const itemStyle: CSSProperties = {
  all: 'unset',
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-select-item-height)',
  padding: '0 var(--ts-select-item-padding-x)',
  paddingLeft: 'calc(var(--ts-select-item-padding-x) + 20px)',
  color: 'var(--ts-select-item-text)',
  fontSize: 'var(--ts-input-font-size)',
  fontFamily: 'inherit',
  cursor: 'pointer',
  userSelect: 'none',
  boxSizing: 'border-box',
  position: 'relative',
};

const itemIndicatorStyle: CSSProperties = {
  position: 'absolute',
  left: 'var(--ts-select-item-padding-x)',
  display: 'inline-flex',
  alignItems: 'center',
  color: 'var(--ts-select-item-check)',
};

const placeholderStyle: CSSProperties = {
  color: 'var(--ts-input-placeholder)',
};

export const Select = forwardRef<HTMLButtonElement, SelectProps>(
  function Select(
    { options, value, onValueChange, placeholder = 'Select...', disabled = false, size = 'md', label },
    ref,
  ) {
    return (
      <SelectPrimitive.Root value={value} onValueChange={onValueChange} disabled={disabled}>
        <SelectPrimitive.Trigger
          ref={ref}
          data-ts-select-trigger=""
          aria-label={label}
          style={{
            ...triggerStyle,
            height: SIZE_HEIGHTS[size],
          }}
        >
          <SelectPrimitive.Value placeholder={<span style={placeholderStyle}>{placeholder}</span>} />
          <SelectPrimitive.Icon style={chevronStyle}>
            <ChevronDown size={14} aria-hidden />
          </SelectPrimitive.Icon>
        </SelectPrimitive.Trigger>

        <SelectPrimitive.Portal>
          <SelectPrimitive.Content
            style={contentStyle}
            position="popper"
            sideOffset={4}
          >
            <SelectPrimitive.Viewport style={viewportStyle}>
              {options.map((option) => (
                <SelectPrimitive.Item
                  key={option.value}
                  value={option.value}
                  data-ts-select-item=""
                  style={itemStyle}
                >
                  <SelectPrimitive.ItemIndicator style={itemIndicatorStyle}>
                    <Check size={14} aria-hidden />
                  </SelectPrimitive.ItemIndicator>
                  <SelectPrimitive.ItemText>{option.label}</SelectPrimitive.ItemText>
                </SelectPrimitive.Item>
              ))}
            </SelectPrimitive.Viewport>
          </SelectPrimitive.Content>
        </SelectPrimitive.Portal>
      </SelectPrimitive.Root>
    );
  },
);

Select.displayName = 'Select';
