import { forwardRef, type ComponentPropsWithoutRef, type CSSProperties, type ElementRef } from 'react';
import { Accordion as RadixAccordion } from 'radix-ui';
import { ChevronDown } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  Accordion                                                                 */
/*  Collapsible sections for settings groups.                                 */
/*  Wraps Radix Accordion — uses --ts-accordion-* tokens.                     */
/* -------------------------------------------------------------------------- */

/* ----- Style injection for animations ------------------------------------ */

const ACCORDION_STYLE_ID = 'ts-accordion-styles';

function ensureAccordionStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(ACCORDION_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = ACCORDION_STYLE_ID;
  sheet.textContent = `
    @keyframes ts-accordion-slide-down {
      from { height: 0; opacity: 0; }
      to { height: var(--radix-accordion-content-height); opacity: 1; }
    }
    @keyframes ts-accordion-slide-up {
      from { height: var(--radix-accordion-content-height); opacity: 1; }
      to { height: 0; opacity: 0; }
    }
    [data-ts-accordion-content][data-state="open"] {
      animation: ts-accordion-slide-down 200ms ease-out;
    }
    [data-ts-accordion-content][data-state="closed"] {
      animation: ts-accordion-slide-up 200ms ease-out;
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-accordion-content][data-state="open"],
      [data-ts-accordion-content][data-state="closed"] {
        animation: none;
      }
    }
    [data-ts-accordion-trigger]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAccordionStyles();
}

/* ----- Accordion.Root ---------------------------------------------------- */

type AccordionRootProps = ComponentPropsWithoutRef<typeof RadixAccordion.Root>;

const Root = forwardRef<ElementRef<typeof RadixAccordion.Root>, AccordionRootProps>(
  ({ style, ...props }, ref) => (
    <RadixAccordion.Root
      ref={ref}
      style={{ borderTop: '1px solid var(--ts-accordion-border)', ...style }}
      {...props}
    />
  ),
);
Root.displayName = 'Accordion';

/* ----- Accordion.Item ---------------------------------------------------- */

const itemStyle: CSSProperties = {
  borderBottom: '1px solid var(--ts-accordion-border)',
};

type AccordionItemProps = ComponentPropsWithoutRef<typeof RadixAccordion.Item>;

const Item = forwardRef<ElementRef<typeof RadixAccordion.Item>, AccordionItemProps>(
  ({ style, ...props }, ref) => (
    <RadixAccordion.Item
      ref={ref}
      style={{ ...itemStyle, ...style }}
      {...props}
    />
  ),
);
Item.displayName = 'Accordion.Item';

/* ----- Accordion.Trigger ------------------------------------------------- */

const triggerStyle: CSSProperties = {
  all: 'unset',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  width: '100%',
  height: 'var(--ts-accordion-header-height)',
  padding: `0 var(--ts-accordion-header-padding-x)`,
  background: 'var(--ts-accordion-header-bg)',
  color: 'var(--ts-accordion-header-text)',
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
  cursor: 'pointer',
  boxSizing: 'border-box',
  transition: 'background 150ms',
};

const chevronStyle: CSSProperties = {
  color: 'var(--ts-accordion-chevron)',
  transition: 'transform 200ms ease',
  flexShrink: 0,
};

type AccordionTriggerProps = ComponentPropsWithoutRef<typeof RadixAccordion.Trigger>;

const Trigger = forwardRef<ElementRef<typeof RadixAccordion.Trigger>, AccordionTriggerProps>(
  ({ children, style, onMouseEnter, onMouseLeave, ...props }, ref) => (
    <RadixAccordion.Header asChild>
      <h3 style={{ all: 'unset' }}>
        <RadixAccordion.Trigger
          ref={ref}
          data-ts-accordion-trigger=""
          style={{ ...triggerStyle, ...style }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = 'var(--ts-accordion-header-bg-hover)';
            onMouseEnter?.(e);
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = 'var(--ts-accordion-header-bg)';
            onMouseLeave?.(e);
          }}
          {...props}
        >
          <span>{children}</span>
          <ChevronDown
            size={16}
            style={{
              ...chevronStyle,
              transform: 'var(--ts-accordion-chevron-rotation, rotate(0deg))',
            }}
            aria-hidden
          />
        </RadixAccordion.Trigger>
      </h3>
    </RadixAccordion.Header>
  ),
);
Trigger.displayName = 'Accordion.Trigger';

/* Inject chevron rotation rule */
const CHEVRON_STYLE_ID = 'ts-accordion-chevron-styles';

function ensureChevronStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(CHEVRON_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = CHEVRON_STYLE_ID;
  sheet.textContent = `
    [data-ts-accordion-trigger][data-state="open"] svg {
      transform: rotate(180deg);
    }
    [data-ts-accordion-trigger][data-state="closed"] svg {
      transform: rotate(0deg);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureChevronStyles();
}

/* ----- Accordion.Content ------------------------------------------------- */

const contentStyle: CSSProperties = {
  overflow: 'hidden',
};

const contentInnerStyle: CSSProperties = {
  padding: 'var(--ts-accordion-content-padding)',
};

type AccordionContentProps = ComponentPropsWithoutRef<typeof RadixAccordion.Content>;

const AccordionContent = forwardRef<ElementRef<typeof RadixAccordion.Content>, AccordionContentProps>(
  ({ children, style, ...props }, ref) => (
    <RadixAccordion.Content
      ref={ref}
      data-ts-accordion-content=""
      style={{ ...contentStyle, ...style }}
      {...props}
    >
      <div style={contentInnerStyle}>{children}</div>
    </RadixAccordion.Content>
  ),
);
AccordionContent.displayName = 'Accordion.Content';

/* ----- Compound export --------------------------------------------------- */

export const Accordion = Object.assign(Root, {
  Item,
  Trigger,
  Content: AccordionContent,
});
