import { useMemo, useCallback, type CSSProperties } from 'react';
import { DropdownMenu } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  LineWidthPicker                                                           */
/*  Dropdown picker for line width in pixels.                                 */
/*  Uses --ts-overlay-* and --ts-menu-* tokens.                               */
/* -------------------------------------------------------------------------- */

export interface LineWidthPickerProps {
  /** Current line width in pixels. */
  value: number;
  /** Called when a new width is selected. */
  onValueChange: (width: number) => void;
  /** Minimum width option (inclusive). Default 1. */
  min?: number;
  /** Maximum width option (inclusive). Default 5. */
  max?: number;
  /** Whether the picker is disabled. */
  disabled?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-line-width-picker-styles';

function ensureLineWidthPickerStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-line-width-picker]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-line-width-picker]:not(:disabled):hover {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-line-width-picker]:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
    [data-ts-line-width-option][data-selected] {
      color: var(--ts-accent-default);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureLineWidthPickerStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const triggerStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-icon-button-size-md)',
  height: 'var(--ts-icon-button-size-md)',
  borderRadius: 'var(--ts-button-radius)',
  border: '1px solid var(--ts-button-ghost-border)',
  background: 'var(--ts-button-ghost-bg)',
  color: 'var(--ts-button-ghost-text)',
  cursor: 'pointer',
  boxSizing: 'border-box',
  transition: 'background 150ms',
  flexShrink: 0,
};

const menuItemContentStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  width: '100%',
};

const menuItemLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
  color: 'var(--ts-text-tertiary)',
  minWidth: 32,
  textAlign: 'right',
};

/* ----- Width preview SVG ------------------------------------------------- */

function WidthPreview({
  width,
  svgWidth = 40,
  svgHeight = 20,
}: {
  width: number;
  svgWidth?: number;
  svgHeight?: number;
}): React.JSX.Element {
  return (
    <svg
      viewBox={`0 0 ${svgWidth} ${svgHeight}`}
      width={svgWidth}
      height={svgHeight}
      aria-hidden="true"
      style={{ flexShrink: 0 }}
    >
      <line
        x1="2"
        y1={svgHeight / 2}
        x2={svgWidth - 2}
        y2={svgHeight / 2}
        stroke="currentColor"
        strokeWidth={width}
        strokeLinecap="round"
      />
    </svg>
  );
}

/* ----- Component --------------------------------------------------------- */

export function LineWidthPicker({
  value,
  onValueChange,
  min = 1,
  max = 5,
  disabled = false,
}: LineWidthPickerProps): React.JSX.Element {
  const widthOptions = useMemo(() => {
    const opts: number[] = [];
    for (let w = min; w <= max; w++) {
      opts.push(w);
    }
    return opts;
  }, [min, max]);

  const handleSelect = useCallback((width: number) => {
    onValueChange(width);
  }, [onValueChange]);

  return (
    <DropdownMenu>
      <DropdownMenu.Trigger>
        <button
          type="button"
          data-ts-line-width-picker=""
          disabled={disabled}
          aria-label="Pick line width"
          style={triggerStyle}
        >
          <WidthPreview width={value} svgWidth={24} svgHeight={16} />
        </button>
      </DropdownMenu.Trigger>
      <DropdownMenu.Content align="start">
        {widthOptions.map((w) => (
          <DropdownMenu.Item
            key={w}
            onSelect={() => handleSelect(w)}
            data-ts-line-width-option=""
            {...(value === w ? { 'data-selected': '' } : {})}
          >
            <div style={menuItemContentStyle}>
              <WidthPreview width={w} />
              <span style={menuItemLabelStyle}>{w}px</span>
            </div>
          </DropdownMenu.Item>
        ))}
      </DropdownMenu.Content>
    </DropdownMenu>
  );
}

LineWidthPicker.displayName = 'LineWidthPicker';
