import { useMemo, useEffect, useRef, useState, useCallback } from 'react';
import { useInstrument, useChannel, CHANNELS, createMessagePackCodec, useFdc3 } from '@deskmodal/fdc3';
import type { CryptoInstrumentContext, Context, Listener } from '@deskmodal/fdc3';
import type { NormalizedTrade } from '@deskmodal/data-layer';
import type {
  OrderBookLevel,
  DepthLevel,
  Trade,
} from '@deskmodal/ui-components';
import { useOrderbookData } from './use-orderbook-data';
import { useDepthStore } from '../store/depth-store';

/** Extended context with optional binary payload. */
interface BroadcastContext extends Context {
  'deskmodal.binary'?: number[];
  'deskmodal.encoding'?: string;
  [key: string]: unknown;
}

/** All data needed to render the Depth app for a given instrument. */
export interface InstrumentDepthData {
  /** Current symbol ticker (e.g., "BTC/USDT"). */
  symbol: string;
  /** Price display precision (decimal places). */
  precision: number;
  /** Mid-market price (null = awaiting data). */
  midPrice: number | null;
  /** Available tick size options for aggregation. */
  tickSizes: number[];
  /** Default aggregation level. */
  defaultAggregation: number;
  /** Order book bid levels. */
  bids: OrderBookLevel[];
  /** Order book ask levels. */
  asks: OrderBookLevel[];
  /** Maximum cumulative total across bids and asks. */
  maxTotal: number;
  /** Depth chart bid levels. */
  depthBids: DepthLevel[];
  /** Depth chart ask levels. */
  depthAsk: DepthLevel[];
  /** Recent trades. */
  trades: Trade[];
  /** The raw FDC3 instrument context, if one has been received. */
  instrumentContext: CryptoInstrumentContext | null;
}

/** Derive price precision from mid price value. */
function derivePrecision(midPrice: number | null): number {
  if (midPrice == null) return 2;
  if (midPrice === 0) return 2;
  if (midPrice >= 1000) return 2;
  if (midPrice >= 1) return 4;
  if (midPrice >= 0.01) return 6;
  return 8;
}

/** Derive appropriate tick sizes from mid price. */
function deriveTickSizes(midPrice: number | null): number[] {
  if (midPrice == null) return [0.01, 0.1, 1];
  if (midPrice === 0) return [0.01, 0.1, 1, 10, 50, 100];
  if (midPrice >= 10000) return [0.01, 0.10, 1.00, 10.00, 50.00, 100.00];
  if (midPrice >= 100) return [0.001, 0.01, 0.10, 1.00, 5.00, 10.00];
  if (midPrice >= 1) return [0.0001, 0.001, 0.01, 0.10, 0.50, 1.00];
  return [0.00000001, 0.0000001, 0.000001, 0.00001, 0.0001, 0.001];
}

/** Derive the default aggregation level from tick sizes. */
function deriveDefaultAggregation(tickSizes: number[]): number {
  return tickSizes[1] ?? tickSizes[0] ?? 0.01;
}

const MAX_TRADES = 100;

/**
 * Auto-insert a slash into a concatenated pair like BTCUSDT → BTC/USDT.
 * Matches the format used by orderbook and trade data channels.
 */
function autoInsertSlash(pair: string): string {
  if (pair.includes('/')) return pair;
  const BASES = [
    'BTC', 'ETH', 'SOL', 'BNB', 'XRP', 'ADA', 'AVAX', 'DOT', 'LINK',
    'MATIC', 'DOGE', 'SHIB', 'UNI', 'LTC', 'ATOM', 'NEAR', 'ARB',
    'OP', 'APT', 'SUI', 'FIL', 'AAVE', 'MKR', 'GBP', 'EUR', 'USD',
    'AUD', 'NZD', 'CAD', 'CHF', 'JPY', 'ZAR', 'SEK', 'NOK',
  ];
  for (const base of BASES) {
    if (pair.startsWith(base) && pair.length > base.length) {
      return `${base}/${pair.slice(base.length)}`;
    }
  }
  if (pair.length >= 6) return `${pair.slice(0, 3)}/${pair.slice(3)}`;
  return pair;
}

/**
 * Listens for FDC3 instrument context changes and provides the current
 * instrument's depth data to the Depth app.
 *
 * Subscribes to the orderbook and trades FDC3 app channels for real-time
 * data. When no data is flowing, returns empty book and trades so the
 * app still renders a meaningful (empty) display.
 */
export function useInstrumentListener(): InstrumentDepthData {
  const instrument = useInstrument();
  const storeSymbol = useDepthStore((s) => s.symbol);
  const setSymbol = useDepthStore((s) => s.setSymbol);

  // Derive the active symbol from FDC3 instrument context or store.
  // Convert concatenated tickers (BTCUSDT) to slash format (BTC/USDT)
  // to match the format used by orderbook/trade data channels.
  const rawTicker = instrument?.id?.ticker ?? (storeSymbol || 'BTCUSDT');
  const activeSymbol = rawTicker ? autoInsertSlash(rawTicker) : 'BTC/USDT';

  // Sync the FDC3 instrument context to the store
  useEffect(() => {
    const ticker = instrument?.id?.ticker;
    if (ticker) {
      const formatted = autoInsertSlash(ticker);
      if (formatted !== storeSymbol) {
        setSymbol(formatted);
      }
    }
  }, [instrument, storeSymbol, setSymbol]);

  // Orderbook/trade subscription intents are deferred until the DeskModal
  // FDC3 app channel routing is fixed. Currently, raising intents on mount
  // can disrupt the Tauri IPC command queue, briefly stalling price delivery
  // to other apps. The price-feed service's connect loop reads the
  // orderbook_symbols set on every (re)connect, so subscriptions added via
  // other mechanisms (e.g., feeds app UI) will still work.

  // Subscribe to orderbook channel data
  const orderbook = useOrderbookData(activeSymbol);

  // Subscribe to trades channel
  const [trades, setTrades] = useState<Trade[]>([]);
  const tradesChannel = useChannel(CHANNELS.TRADES);
  const codecRef = useRef(createMessagePackCodec());

  const addTrade = useCallback((trade: Trade) => {
    setTrades((prev) => {
      const next = [trade, ...prev];
      if (next.length > MAX_TRADES) next.length = MAX_TRADES;
      return next;
    });
  }, []);

  useEffect(() => {
    if (!tradesChannel) return;

    let listener: Listener | undefined;
    let cancelled = false;

    const listenerPromise = tradesChannel.addContextListener(
      null, // Listen for all types, filter by dataType field
      (ctx) => {
        if (cancelled) return;
        // Only process trade contexts (identified by dataType field)
        const raw = ctx as unknown as Record<string, unknown>;
        if (raw.dataType !== 'trade') return;

        const context = ctx as BroadcastContext;
        let tradeData: { symbol: string; price: number; quantity: number; side: string; timestamp: number; tradeId: string };

        if (
          context['deskmodal.encoding'] === 'msgpack' &&
          context['deskmodal.binary']
        ) {
          const binary = new Uint8Array(context['deskmodal.binary'] as number[]).buffer;
          tradeData = codecRef.current.decode(binary);
        } else {
          // Transform FDC3 context fields from the price-feed service format
          const raw = ctx as unknown as Record<string, unknown>;
          const ticker = (raw.id as Record<string, string> | undefined)?.ticker ?? '';
          tradeData = {
            symbol: ticker,
            price: (raw.price as number) ?? 0,
            quantity: (raw.quantity as number) ?? 0,
            side: (raw.side as string) ?? 'buy',
            timestamp: (raw.timestamp as number) ?? Date.now(),
            tradeId: (raw.tradeId as string) ?? '',
          };
        }

        // Filter to current symbol
        // Normalize: service sends "BTCUSDT", app uses "BTC/USDT"
        const norm = (s: string) => s.replace(/[/-]/g, '').toUpperCase();
        if (activeSymbol && tradeData.symbol && norm(tradeData.symbol) !== norm(activeSymbol)) return;

        const trade: Trade = {
          id: tradeData.tradeId || `${tradeData.timestamp}`,
          time: new Date(tradeData.timestamp).toISOString(),
          price: tradeData.price,
          size: tradeData.quantity,
          side: tradeData.side === 'buy' ? 'buy' : 'sell',
          significant: tradeData.quantity > 1.0,
        };

        addTrade(trade);
      },
    );

    listenerPromise.then(
      (l) => {
        if (cancelled) {
          l.unsubscribe();
        } else {
          listener = l;
        }
      },
      () => {
        // Listener registration failed
      },
    );

    return () => {
      cancelled = true;
      if (listener) {
        listener.unsubscribe();
      }
    };
  }, [tradesChannel, activeSymbol, addTrade]);

  // Reset trades when symbol changes
  useEffect(() => {
    setTrades([]);
  }, [activeSymbol]);

  return useMemo<InstrumentDepthData>(() => {
    const precision = derivePrecision(orderbook.midPrice);
    const tickSizes = deriveTickSizes(orderbook.midPrice);
    const defaultAggregation = deriveDefaultAggregation(tickSizes);

    const uiBids: OrderBookLevel[] = orderbook.bids;
    const uiAsks: OrderBookLevel[] = orderbook.asks;

    const maxTotal = Math.max(
      uiBids[uiBids.length - 1]?.total ?? 0,
      uiAsks[uiAsks.length - 1]?.total ?? 0,
    );

    const depthBids: DepthLevel[] = uiBids.map((l) => ({
      price: l.price,
      cumulativeVolume: l.total,
    }));

    const depthAsks: DepthLevel[] = uiAsks.map((l) => ({
      price: l.price,
      cumulativeVolume: l.total,
    }));

    return {
      symbol: activeSymbol || 'No instrument',
      precision,
      midPrice: orderbook.midPrice,
      tickSizes,
      defaultAggregation,
      bids: uiBids,
      asks: uiAsks,
      maxTotal,
      depthBids,
      depthAsk: depthAsks,
      trades,
      instrumentContext: instrument,
    };
  }, [activeSymbol, orderbook, trades, instrument]);
}
