import { useEffect, useState } from 'react';
import { useFdc3, INTENTS } from '@deskmodal/fdc3';
import type { Context, Listener, CryptoInstrumentContext } from '@deskmodal/fdc3';
import { useDepthStore } from '../store/depth-store';

export interface DepthIntentResult {
  /** Symbol from the most recently received ViewDepth intent, if any. */
  readonly pendingSymbol: string | null;
}

/**
 * Auto-insert a slash into a concatenated pair like BTCUSDT -> BTC/USDT.
 * Matches the format used by orderbook and trade data channels.
 */
function autoInsertSlash(pair: string): string {
  if (pair.includes('/')) return pair;
  const BASES = [
    'BTC', 'ETH', 'SOL', 'BNB', 'XRP', 'ADA', 'AVAX', 'DOT', 'LINK',
    'MATIC', 'DOGE', 'SHIB', 'UNI', 'LTC', 'ATOM', 'NEAR', 'ARB',
    'OP', 'APT', 'SUI', 'FIL', 'AAVE', 'MKR', 'GBP', 'EUR', 'USD',
    'AUD', 'NZD', 'CAD', 'CHF', 'JPY', 'ZAR', 'SEK', 'NOK',
  ];
  for (const base of BASES) {
    if (pair.startsWith(base) && pair.length > base.length) {
      return `${base}/${pair.slice(base.length)}`;
    }
  }
  if (pair.length >= 6) return `${pair.slice(0, 3)}/${pair.slice(3)}`;
  return pair;
}

/**
 * Register a handler for the `deskmodal.ViewDepth` intent.
 *
 * When the intent is received with an instrument context, switches the depth
 * store to the specified symbol. Returns the pending symbol for components
 * that need to react to intent-driven navigation.
 */
export function useDepthIntent(): DepthIntentResult {
  const fdc3 = useFdc3();
  const setSymbol = useDepthStore((s) => s.setSymbol);
  const [pendingSymbol, setPendingSymbol] = useState<string | null>(null);

  useEffect(() => {
    if (!fdc3) return;

    let listener: Listener | undefined;
    let cancelled = false;

    const listenerPromise = fdc3.addIntentListener(
      INTENTS.ViewDepth,
      async (context: Context) => {
        if (cancelled) return;

        const instrument = context as CryptoInstrumentContext;
        const ticker = instrument.id?.ticker;
        if (!ticker) return;

        const normalized = autoInsertSlash(ticker);
        setSymbol(normalized);
        setPendingSymbol(normalized);
      },
    );

    listenerPromise.then(
      (l) => {
        if (cancelled) {
          l.unsubscribe();
        } else {
          listener = l;
        }
      },
      () => {
        // Intent listener registration failed — nothing to clean up
      },
    );

    return () => {
      cancelled = true;
      if (listener) {
        listener.unsubscribe();
      }
    };
  }, [fdc3, setSymbol]);

  return { pendingSymbol };
}
