import { forwardRef, useMemo, type CSSProperties } from 'react';
import { Panel, ScrollArea, Checkbox, IconButton } from '../primitives';
import {
  Settings,
  Trash2,
  Lock,
  Unlock,
  TrendingUp,
  PenTool,
  Play,
  Layers,
} from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ObjectTreePanel                                                           */
/*  Panel listing all chart objects (indicators, drawings, strategies).       */
/*  Uses --ts-panel-*, --ts-data-* tokens.                                    */
/* -------------------------------------------------------------------------- */

export interface ObjectTreeItem {
  /** Unique identifier. */
  id: string;
  /** Display label. */
  label: string;
  /** Object type for icon selection. */
  type: 'indicator' | 'drawing' | 'strategy';
  /** Whether the object is visible on the chart. */
  visible: boolean;
  /** Whether the object is locked (drawings only). */
  locked?: boolean;
  /** Color associated with this object. */
  color?: string;
}

export interface ObjectTreePanelProps {
  /** Items to display in the tree. */
  items: ObjectTreeItem[];
  /** Called when an item's visibility is toggled. */
  onVisibilityToggle?: (itemId: string) => void;
  /** Called when an item's lock state is toggled. */
  onLockToggle?: (itemId: string) => void;
  /** Called when an item's settings are requested. */
  onSettings?: (itemId: string) => void;
  /** Called when an item is removed. */
  onRemove?: (itemId: string) => void;
  /** Called when an item is selected (focused). */
  onSelect?: (itemId: string) => void;
  /** Currently selected item id. */
  selectedId?: string;
}

/* ----- Style injection --------------------------------------------------- */

const OBJECT_TREE_STYLE_ID = 'ts-object-tree-styles';

function ensureObjectTreeStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(OBJECT_TREE_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = OBJECT_TREE_STYLE_ID;
  sheet.textContent = `
    [data-ts-object-tree-item]:hover {
      background: var(--ts-data-row-bg-hover);
    }
    [data-ts-object-tree-item] [data-ts-ot-actions] {
      opacity: 0;
      transition: opacity 150ms;
    }
    [data-ts-object-tree-item]:hover [data-ts-ot-actions],
    [data-ts-object-tree-item]:focus-within [data-ts-ot-actions] {
      opacity: 1;
    }
    [data-ts-object-tree-item][data-selected] {
      background: var(--ts-data-row-bg-selected);
    }
    [data-ts-object-tree-item]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureObjectTreeStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const itemStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-data-row-height)',
  padding: `0 var(--ts-data-row-padding-x)`,
  gap: 'var(--ts-space-2)',
  cursor: 'pointer',
  userSelect: 'none',
  fontSize: 'var(--ts-data-cell-font-size)',
  borderBottom: '1px solid var(--ts-data-row-border)',
  boxSizing: 'border-box',
  outline: 'none',
};

const colorDotStyle = (dotColor: string): CSSProperties => ({
  width: 8,
  height: 8,
  borderRadius: '50%',
  background: dotColor,
  flexShrink: 0,
});

const typeIconStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  flexShrink: 0,
};

const labelStyle: CSSProperties = {
  flex: '1 1 auto',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
  color: 'var(--ts-text-primary)',
};

const actionsStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '2px',
  flexShrink: 0,
};

const groupLabelStyle: CSSProperties = {
  padding: `var(--ts-space-1) var(--ts-data-row-padding-x)`,
  fontSize: 'var(--ts-font-xs)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-text-tertiary)',
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
  userSelect: 'none',
};

const emptyStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  padding: 'var(--ts-space-6)',
  gap: 'var(--ts-space-2)',
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-sm)',
  textAlign: 'center',
};

/* ----- Helpers ----------------------------------------------------------- */

function getTypeIcon(type: ObjectTreeItem['type']): React.JSX.Element {
  switch (type) {
    case 'indicator':
      return <TrendingUp size={14} style={typeIconStyle} aria-hidden />;
    case 'drawing':
      return <PenTool size={14} style={typeIconStyle} aria-hidden />;
    case 'strategy':
      return <Play size={14} style={typeIconStyle} aria-hidden />;
  }
}

export const ObjectTreePanel = forwardRef<HTMLDivElement, ObjectTreePanelProps>(
  function ObjectTreePanel(
    {
      items,
      onVisibilityToggle,
      onLockToggle,
      onSettings,
      onRemove,
      onSelect,
      selectedId,
    },
    ref,
  ) {
    const { indicators, drawings, strategies } = useMemo(() => {
      const ind: ObjectTreeItem[] = [];
      const drw: ObjectTreeItem[] = [];
      const str: ObjectTreeItem[] = [];
      for (const item of items) {
        switch (item.type) {
          case 'indicator':
            ind.push(item);
            break;
          case 'drawing':
            drw.push(item);
            break;
          case 'strategy':
            str.push(item);
            break;
        }
      }
      return { indicators: ind, drawings: drw, strategies: str };
    }, [items]);

    if (items.length === 0) {
      return (
        <Panel ref={ref} title="Objects">
          <div data-ts-object-tree="" style={emptyStyle} role="status">
            <Layers size={24} aria-hidden />
            <span>No objects on chart</span>
            <span style={{ fontSize: 'var(--ts-font-xs)' }}>
              Add indicators or draw on the chart to see them here
            </span>
          </div>
        </Panel>
      );
    }

    function renderItem(item: ObjectTreeItem): React.JSX.Element {
      const isSelected = item.id === selectedId;
      const isDrawing = item.type === 'drawing';

      return (
        <div
          key={item.id}
          data-ts-object-tree-item=""
          {...(isSelected ? { 'data-selected': '' } : {})}
          style={itemStyle}
          tabIndex={0}
          role="row"
          aria-selected={isSelected}
          onClick={() => onSelect?.(item.id)}
          onKeyDown={(e) => {
            if (e.key === 'Enter' || e.key === ' ') {
              e.preventDefault();
              onSelect?.(item.id);
            }
          }}
        >
          <Checkbox
            checked={item.visible}
            onCheckedChange={() => onVisibilityToggle?.(item.id)}
          />
          {item.color !== undefined && (
            <span style={colorDotStyle(item.color)} aria-hidden />
          )}
          {getTypeIcon(item.type)}
          <span style={labelStyle}>{item.label}</span>
          <span data-ts-ot-actions="" style={actionsStyle}>
            {onSettings !== undefined && (
              <IconButton
                icon={<Settings size={12} />}
                label={`Settings for ${item.label}`}
                variant="ghost"
                size="sm"
                onClick={(e) => {
                  e.stopPropagation();
                  onSettings(item.id);
                }}
              />
            )}
            {isDrawing && onLockToggle !== undefined && (
              <IconButton
                icon={item.locked ? <Lock size={12} /> : <Unlock size={12} />}
                label={item.locked ? `Unlock ${item.label}` : `Lock ${item.label}`}
                variant="ghost"
                size="sm"
                onClick={(e) => {
                  e.stopPropagation();
                  onLockToggle(item.id);
                }}
              />
            )}
            {onRemove !== undefined && (
              <IconButton
                icon={<Trash2 size={12} />}
                label={`Remove ${item.label}`}
                variant="ghost"
                size="sm"
                onClick={(e) => {
                  e.stopPropagation();
                  onRemove(item.id);
                }}
              />
            )}
          </span>
        </div>
      );
    }

    return (
      <Panel ref={ref} title="Objects">
        <div data-ts-object-tree="" role="grid" aria-label="Chart objects">
          <ScrollArea>
            {indicators.length > 0 && (
              <>
                <div style={groupLabelStyle}>Indicators</div>
                {indicators.map(renderItem)}
              </>
            )}
            {strategies.length > 0 && (
              <>
                <div style={groupLabelStyle}>Strategies</div>
                {strategies.map(renderItem)}
              </>
            )}
            {drawings.length > 0 && (
              <>
                <div style={groupLabelStyle}>Drawings</div>
                {drawings.map(renderItem)}
              </>
            )}
          </ScrollArea>
        </div>
      </Panel>
    );
  },
);

ObjectTreePanel.displayName = 'ObjectTreePanel';
