import { useState, useEffect, useRef } from "react";
import type { Channel } from "../fdc3-types";
import { useFdc3 } from "./use-fdc3";

/**
 * Hook for managing an app channel subscription.
 *
 * Gets or creates an app channel by ID. Returns null until both FDC3 is
 * available and the channel has been resolved.
 *
 * Usage:
 *   const channel = useChannel("deskmodal.prices");
 *   useEffect(() => {
 *     if (!channel) return;
 *     const listenerPromise = channel.addContextListener("deskmodal.ohlcv", handleOHLCV);
 *     return () => { listenerPromise.then(l => l.unsubscribe()); };
 *   }, [channel]);
 */
export function useChannel(channelId: string): Channel | null {
  const fdc3 = useFdc3();
  const [channel, setChannel] = useState<Channel | null>(null);
  const resolvedForRef = useRef<string | null>(null);
  const fdc3Ref = useRef(fdc3);
  fdc3Ref.current = fdc3;

  useEffect(() => {
    if (!fdc3) return;

    // Skip re-resolution if we already resolved this channelId
    if (resolvedForRef.current === channelId && channel !== null) return;

    let cancelled = false;

    fdc3.getOrCreateChannel(channelId).then(
      (ch) => {
        if (!cancelled) {
          resolvedForRef.current = channelId;
          setChannel(ch);
        }
      },
      () => {
        if (!cancelled) {
          setChannel(null);
        }
      }
    );

    return () => {
      cancelled = true;
    };
    // Only depend on channelId — not fdc3 reference (which may change on re-render)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [channelId]);

  // If fdc3 becomes available after initial mount, resolve
  useEffect(() => {
    if (fdc3 && resolvedForRef.current !== channelId) {
      fdc3.getOrCreateChannel(channelId).then(
        (ch) => {
          resolvedForRef.current = channelId;
          setChannel(ch);
        },
        () => {},
      );
    }
  }, [fdc3, channelId]);

  return channel;
}
