import { useCallback, useMemo, useState, type CSSProperties } from 'react';
import { Dialog, Tabs, Input, Button } from '../../primitives';
import { ConditionBuilder, type ConditionConfig } from './ConditionBuilder';
import { AlertFrequencySelector, type AlertFrequency } from './AlertFrequencySelector';
import { NotificationChannelConfig, type AlertChannel } from './NotificationChannelConfig';
import { WebhookConfig } from './WebhookConfig';
import { AlertTemplateManager } from './AlertTemplateManager';

/* -------------------------------------------------------------------------- */
/*  AlertCreatorDialog                                                        */
/*  Compound dialog for creating alerts with condition builder, frequency,    */
/*  notification configuration, and template management.                      */
/*  Uses --ts-dialog-*, --ts-tab-*, --ts-input-* tokens.                     */
/* -------------------------------------------------------------------------- */

export interface AlertConfig {
  id: string;
  symbol: string;
  conditions: ConditionConfig[];
  logicOperator: 'and' | 'or';
  frequency: AlertFrequency;
  channels: AlertChannel[];
  webhookUrl?: string;
  webhookMethod?: 'GET' | 'POST' | 'PUT';
  webhookHeaders?: Array<{ key: string; value: string }>;
  webhookPayloadTemplate?: string;
  name?: string;
  message?: string;
  soundId?: string;
}

export interface AlertCreatorDialogProps {
  /** Whether the dialog is open. */
  open: boolean;
  /** Called when the dialog open state changes. */
  onOpenChange: (open: boolean) => void;
  /** Pre-filled symbol (e.g., from chart context). */
  defaultSymbol?: string;
  /** Pre-filled price level (e.g., from right-click on chart). */
  defaultPrice?: number;
  /** Available alert sources (symbol price, indicators, custom). */
  sources: Array<{ value: string; label: string; group: string }>;
  /** Available alert operators. */
  operators: Array<{ value: string; label: string }>;
  /** Available alert templates. */
  templates: Array<{ id: string; name: string }>;
  /** Called when an alert is created. Receives the full alert configuration. */
  onAlertCreate: (config: AlertConfig) => void;
  /** Called when a template is saved. */
  onTemplateSave?: (name: string) => void;
  /** Called when a template is deleted. */
  onTemplateDelete?: (templateId: string) => void;
  /** Called when a template is loaded. */
  onTemplateLoad?: (templateId: string) => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-alert-creator-dialog-styles';

function ensureAlertCreatorDialogStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-alert-creator-dialog] textarea {
      width: 100%;
      min-height: 60px;
      padding: var(--ts-space-2);
      background: var(--ts-input-bg);
      color: var(--ts-input-text);
      border: 1px solid var(--ts-input-border);
      border-radius: var(--ts-input-radius);
      font-size: var(--ts-font-sm);
      font-family: inherit;
      resize: vertical;
      box-sizing: border-box;
      transition: border-color 150ms;
    }
    [data-ts-alert-creator-dialog] textarea:focus {
      border-color: var(--ts-input-border-focus);
      outline: 1px solid var(--ts-input-border-focus);
      outline-offset: -1px;
    }
    [data-ts-alert-creator-dialog] textarea:hover {
      border-color: var(--ts-input-border-hover);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAlertCreatorDialogStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const contentStyle: CSSProperties = {
  maxWidth: 520,
};

const tabContentStyle: CSSProperties = {
  padding: 'var(--ts-space-3) 0',
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-4)',
};

const sectionLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-text-secondary)',
  fontFamily: 'inherit',
  marginBottom: 'var(--ts-space-1)',
};

const footerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  paddingTop: 'var(--ts-space-3)',
  borderTop: '1px solid var(--ts-border-subtle)',
  marginTop: 'var(--ts-space-3)',
};

const footerActionsStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const placeholderHintStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'inherit',
  marginTop: 'var(--ts-space-1)',
};

/* ----- Default frequency options ----------------------------------------- */

const FREQUENCY_OPTIONS = [
  { value: 'once' as const, label: 'Once', description: 'Triggers once, then expires' },
  { value: 'every_time' as const, label: 'Every time', description: 'Triggers on every matching tick' },
  { value: 'once_per_bar' as const, label: 'Once per bar', description: 'Triggers once per bar period' },
  { value: 'once_per_bar_close' as const, label: 'Once per bar close', description: 'Triggers at bar close only' },
];

const DEFAULT_SOUNDS = [
  { id: 'chime', label: 'Chime' },
  { id: 'bell', label: 'Bell' },
  { id: 'alert', label: 'Alert Tone' },
  { id: 'ding', label: 'Ding' },
];

/* ----- Component --------------------------------------------------------- */

export function AlertCreatorDialog({
  open,
  onOpenChange,
  defaultSymbol,
  defaultPrice,
  sources,
  operators,
  templates,
  onAlertCreate,
  onTemplateSave,
  onTemplateDelete,
  onTemplateLoad,
}: AlertCreatorDialogProps): React.JSX.Element {
  // Condition state
  const initialCondition = useMemo((): ConditionConfig => ({
    id: `cond-init`,
    source: defaultSymbol ?? sources[0]?.value ?? '',
    operator: operators[0]?.value ?? '',
    value: defaultPrice ?? 0,
  }), [defaultSymbol, defaultPrice, sources, operators]);

  const [conditions, setConditions] = useState<ConditionConfig[]>([initialCondition]);
  const [logicOperator, setLogicOperator] = useState<'and' | 'or'>('and');
  const [frequency, setFrequency] = useState<AlertFrequency>('once');

  // Notification state
  const [alertName, setAlertName] = useState('');
  const [alertMessage, setAlertMessage] = useState('');
  const [channels, setChannels] = useState<AlertChannel[]>(['app']);
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [soundId, setSoundId] = useState('chime');

  // Webhook state
  const [webhookUrl, setWebhookUrl] = useState('');
  const [webhookMethod, setWebhookMethod] = useState<'GET' | 'POST' | 'PUT'>('POST');
  const [webhookHeaders, setWebhookHeaders] = useState<Array<{ key: string; value: string }>>([]);
  const [webhookPayload, setWebhookPayload] = useState('');

  const hasConditions = conditions.length > 0 && conditions[0]!.source !== '';

  const handleCreate = useCallback(() => {
    if (!hasConditions) return;

    const config: AlertConfig = {
      id: `alert-${Date.now()}`,
      symbol: defaultSymbol ?? conditions[0]!.source,
      conditions,
      logicOperator,
      frequency,
      channels,
      name: alertName || undefined,
      message: alertMessage || undefined,
      soundId: soundEnabled ? soundId : undefined,
    };

    if (channels.includes('webhook')) {
      config.webhookUrl = webhookUrl;
      config.webhookMethod = webhookMethod;
      config.webhookHeaders = webhookHeaders.length > 0 ? webhookHeaders : undefined;
      config.webhookPayloadTemplate = webhookPayload || undefined;
    }

    onAlertCreate(config);
    onOpenChange(false);
  }, [
    hasConditions, conditions, logicOperator, frequency, channels,
    alertName, alertMessage, soundEnabled, soundId,
    webhookUrl, webhookMethod, webhookHeaders, webhookPayload,
    defaultSymbol, onAlertCreate, onOpenChange,
  ]);

  const handleCancel = useCallback(() => {
    onOpenChange(false);
  }, [onOpenChange]);

  const showWebhookConfig = channels.includes('webhook');

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content style={contentStyle} data-ts-alert-creator-dialog="">
        <Dialog.Title>Create Alert</Dialog.Title>
        <Dialog.Description>
          {defaultSymbol ? `Set up an alert for ${defaultSymbol}` : 'Configure alert conditions and notifications'}
        </Dialog.Description>

        <Tabs defaultValue="condition">
          <Tabs.List>
            <Tabs.Trigger value="condition">Condition</Tabs.Trigger>
            <Tabs.Trigger value="notifications">Notifications</Tabs.Trigger>
          </Tabs.List>

          {/* Condition tab */}
          <Tabs.Content value="condition">
            <div style={tabContentStyle}>
              <ConditionBuilder
                conditions={conditions}
                onConditionsChange={setConditions}
                logicOperator={logicOperator}
                onLogicOperatorChange={setLogicOperator}
                sources={sources}
                operators={operators}
              />
              <AlertFrequencySelector
                value={frequency}
                onValueChange={setFrequency}
                options={FREQUENCY_OPTIONS}
              />
            </div>
          </Tabs.Content>

          {/* Notifications tab */}
          <Tabs.Content value="notifications">
            <div style={tabContentStyle}>
              <div>
                <span style={sectionLabelStyle}>Alert name</span>
                <Input
                  value={alertName}
                  onChange={(e) => setAlertName(e.target.value)}
                  placeholder="My alert"
                  size="sm"
                  data-testid="alert-name-input"
                />
              </div>

              <div>
                <span style={sectionLabelStyle}>Message</span>
                <textarea
                  value={alertMessage}
                  onChange={(e) => setAlertMessage(e.target.value)}
                  placeholder="Alert triggered for {{ticker}} at {{close}}"
                  data-testid="alert-message-input"
                />
                <span style={placeholderHintStyle}>
                  {'Placeholders: {{ticker}}, {{close}}, {{price}}, {{exchange}}'}
                </span>
              </div>

              <NotificationChannelConfig
                enabledChannels={channels}
                onChannelsChange={setChannels}
                soundEnabled={soundEnabled}
                onSoundEnabledChange={setSoundEnabled}
                selectedSoundId={soundId}
                onSoundChange={setSoundId}
                sounds={DEFAULT_SOUNDS}
              />

              {showWebhookConfig ? (
                <WebhookConfig
                  url={webhookUrl}
                  onUrlChange={setWebhookUrl}
                  method={webhookMethod}
                  onMethodChange={setWebhookMethod}
                  headers={webhookHeaders}
                  onHeadersChange={setWebhookHeaders}
                  payloadTemplate={webhookPayload}
                  onPayloadTemplateChange={setWebhookPayload}
                  showPreview
                />
              ) : null}
            </div>
          </Tabs.Content>
        </Tabs>

        {/* Footer */}
        <div style={footerStyle}>
          <AlertTemplateManager
            templates={templates}
            onTemplateLoad={(id) => onTemplateLoad?.(id)}
            onTemplateSave={(name) => onTemplateSave?.(name)}
            onTemplateDelete={(id) => onTemplateDelete?.(id)}
          />
          <div style={footerActionsStyle}>
            <Button
              variant="secondary"
              size="sm"
              onClick={handleCancel}
              data-testid="cancel-button"
            >
              Cancel
            </Button>
            <Button
              variant="primary"
              size="sm"
              onClick={handleCreate}
              disabled={!hasConditions}
              data-testid="create-button"
            >
              Create
            </Button>
          </div>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

AlertCreatorDialog.displayName = 'AlertCreatorDialog';
