import { forwardRef, type CSSProperties, type ReactNode } from 'react';
import { ScrollArea as RadixScrollArea } from 'radix-ui';

export interface ScrollAreaProps {
  /** Content to scroll */
  children: ReactNode;
  /** Scrollbar visibility strategy */
  type?: 'auto' | 'always' | 'scroll' | 'hover';
  /** Additional class name */
  className?: string;
}

const rootStyle: CSSProperties = {
  overflow: 'hidden',
};

const viewportStyle: CSSProperties = {
  width: '100%',
  height: '100%',
};

const scrollbarBaseStyle: CSSProperties = {
  display: 'flex',
  userSelect: 'none',
  touchAction: 'none',
  transition: `background var(--ts-duration-micro) ease`,
  background: 'var(--ts-scrollarea-track)',
};

const verticalScrollbarStyle: CSSProperties = {
  ...scrollbarBaseStyle,
  width: 'var(--ts-scrollarea-size)',
  padding: '2px',
};

const horizontalScrollbarStyle: CSSProperties = {
  ...scrollbarBaseStyle,
  flexDirection: 'column',
  height: 'var(--ts-scrollarea-size)',
  padding: '2px',
};

const thumbStyle: CSSProperties = {
  flex: 1,
  background: 'var(--ts-scrollarea-thumb)',
  borderRadius: 'var(--ts-scrollarea-radius)',
  position: 'relative',
  transition: `background var(--ts-duration-micro) ease`,
};

const cornerStyle: CSSProperties = {
  background: 'var(--ts-scrollarea-track)',
};

export const ScrollArea = forwardRef<HTMLDivElement, ScrollAreaProps>(
  function ScrollArea({ children, type = 'hover', className }, ref) {
    return (
      <RadixScrollArea.Root
        ref={ref}
        type={type}
        className={className}
        style={rootStyle}
      >
        <RadixScrollArea.Viewport style={viewportStyle}>
          {children}
        </RadixScrollArea.Viewport>

        <RadixScrollArea.Scrollbar
          orientation="vertical"
          style={verticalScrollbarStyle}
        >
          <RadixScrollArea.Thumb
            style={thumbStyle}
            onMouseEnter={(e) => {
              e.currentTarget.style.background = 'var(--ts-scrollarea-thumb-hover)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.background = 'var(--ts-scrollarea-thumb)';
            }}
          />
        </RadixScrollArea.Scrollbar>

        <RadixScrollArea.Scrollbar
          orientation="horizontal"
          style={horizontalScrollbarStyle}
        >
          <RadixScrollArea.Thumb
            style={thumbStyle}
            onMouseEnter={(e) => {
              e.currentTarget.style.background = 'var(--ts-scrollarea-thumb-hover)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.background = 'var(--ts-scrollarea-thumb)';
            }}
          />
        </RadixScrollArea.Scrollbar>

        <RadixScrollArea.Corner style={cornerStyle} />
      </RadixScrollArea.Root>
    );
  },
);
