import {
  useRef,
  type CSSProperties,
  type ReactNode,
} from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { ScrollArea } from './ScrollArea';

/* -------------------------------------------------------------------------- */
/*  VirtualList                                                                */
/*  Virtualized scrolling list for large datasets (watchlists, search).        */
/*  Wraps @tanstack/react-virtual and delegates rendering via renderItem.      */
/*  Uses ScrollArea for styled scrollbars matching Desk theme tokens.          */
/* -------------------------------------------------------------------------- */

export interface VirtualListProps<TItem> {
  /** Items to render. */
  items: TItem[];
  /** Render callback for each visible item. Receives the item and its index. */
  renderItem: (item: TItem, index: number) => ReactNode;
  /** Fixed height for each item in pixels. */
  itemHeight: number;
  /** Number of items to render outside the visible window. */
  overscan?: number;
  /** Additional CSS class name on the root element. */
  className?: string;
}

const rootStyle: CSSProperties = {
  width: '100%',
  height: '100%',
  position: 'relative',
};

const scrollContainerStyle: CSSProperties = {
  width: '100%',
  height: '100%',
  overflow: 'auto',
};

const itemStyle: CSSProperties = {
  position: 'absolute',
  top: 0,
  left: 0,
  width: '100%',
};

/**
 * VirtualListInner renders items using TanStack Virtual with a direct
 * scrollable div. VirtualList wraps it in ScrollArea for styled scrollbars
 * in real browsers while keeping a direct scroll ref for the virtualizer.
 */
export function VirtualList<TItem>({
  items,
  renderItem,
  itemHeight,
  overscan = 5,
  className,
}: VirtualListProps<TItem>) {
  const scrollElementRef = useRef<HTMLDivElement>(null);

  const virtualizer = useVirtualizer({
    count: items.length,
    getScrollElement: () => scrollElementRef.current,
    estimateSize: () => itemHeight,
    overscan,
  });

  const virtualItems = virtualizer.getVirtualItems();
  const totalSize = virtualizer.getTotalSize();

  return (
    <div data-ts-virtual-list="" className={className} style={rootStyle}>
      <ScrollArea>
        <div
          ref={scrollElementRef}
          data-ts-virtual-list-scroll=""
          style={scrollContainerStyle}
        >
          <div
            style={{
              height: `${totalSize}px`,
              width: '100%',
              position: 'relative',
            }}
          >
            {virtualItems.map((virtualRow) => {
              const item = items[virtualRow.index];
              if (item === undefined) return null;
              return (
                <div
                  key={virtualRow.key}
                  data-ts-virtual-list-item=""
                  style={{
                    ...itemStyle,
                    height: `${itemHeight}px`,
                    transform: `translateY(${virtualRow.start}px)`,
                  }}
                >
                  {renderItem(item, virtualRow.index)}
                </div>
              );
            })}
          </div>
        </div>
      </ScrollArea>
    </div>
  );
}

VirtualList.displayName = 'VirtualList';
