/* ----- Component --------------------------------------------------------- */

export function SymbolSearchDialog({
  open,
  onOpenChange,
  onSymbolSelect,
  results,
  query,
  onQueryChange,
  assetFilter,
  onAssetFilterChange,
  recentSearches,
  loading = false,
}: SymbolSearchDialogProps): React.JSX.Element {
  const [focusedIndex, setFocusedIndex] = useState(-1);
  const inputRef = useRef<HTMLInputElement>(null);

  const displayItems = query.length === 0 && recentSearches && recentSearches.length > 0
    ? recentSearches
    : results;
  const showRecentsLabel = query.length === 0 && recentSearches && recentSearches.length > 0;

  useEffect(() => {
    if (open) {
      setFocusedIndex(-1);
      requestAnimationFrame(() => {
        inputRef.current?.focus();
      });
    }
  }, [open]);

  useEffect(() => {
    setFocusedIndex(-1);
  }, [query, assetFilter]);

  const handleKeyDown = useCallback((e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setFocusedIndex((prev) => Math.min(prev + 1, displayItems.length - 1));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setFocusedIndex((prev) => Math.max(prev - 1, -1));
    } else if (e.key === 'Enter' && focusedIndex >= 0 && focusedIndex < displayItems.length) {
      e.preventDefault();
      onSymbolSelect(displayItems[focusedIndex]!);
    }
  }, [focusedIndex, displayItems, onSymbolSelect]);

  const handleResultClick = useCallback((result: SymbolSearchResult) => {
    onSymbolSelect(result);
  }, [onSymbolSelect]);

  const renderResultItem = useCallback((item: SymbolSearchResult, index: number) => (
    <div
      key={`${item.symbol}-${item.exchange}`}
      data-ts-symbol-search-result=""
      {...(index === focusedIndex ? { 'data-focused': '' } : {})}
      role="option"
      aria-selected={index === focusedIndex}
      tabIndex={-1}
      style={resultItemStyle}
      onClick={() => handleResultClick(item)}
    >
      {item.exchangeIcon ? (
        <div style={resultExchangeIconStyle}>{item.exchangeIcon}</div>
      ) : null}
      <span style={resultSymbolStyle}>{item.symbol}</span>
      <span style={resultDescriptionStyle}>{item.description}</span>
      {item.subType ? <Badge>{item.subType}</Badge> : null}
      <span style={resultExchangeStyle}>{item.exchange}</span>
    </div>
  ), [focusedIndex, handleResultClick]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content
        data-ts-symbol-search=""
        style={dialogContentStyle}
        showClose
        aria-describedby={undefined}
      >
        <Dialog.Title style={visuallyHiddenStyle}>Search Symbols</Dialog.Title>

        {/* Search input */}
        <div style={searchHeaderStyle} data-ts-symbol-search-input="">
          <Search size={16} style={searchIconStyle} aria-hidden />
          <Input
            ref={inputRef}
            size="md"
            value={query}
            onChange={(e) => onQueryChange(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Search symbol..."
            aria-label="Search symbols"
            style={{
              flex: 1,
              border: 'none',
              background: 'transparent',
              outline: 'none',
            }}
          />
        </div>

        {/* Filter chips */}
        <div style={filtersRowStyle} data-ts-symbol-search-filters="" role="tablist" aria-label="Asset type filters">
          {ASSET_FILTERS.map((f) => (
            <button
              key={f.value}
              type="button"
              data-ts-symbol-search-filter=""
              {...(assetFilter === f.value ? { 'data-active': '' } : {})}
              role="tab"
              aria-selected={assetFilter === f.value}
              style={assetFilter === f.value ? filterActiveStyle : filterInactiveStyle}
              onClick={() => onAssetFilterChange(f.value)}
            >
              {f.label}
            </button>
          ))}
        </div>

        {/* Results area */}
        <div style={resultsContainerStyle} role="listbox" aria-label="Symbol results">
          {loading ? (
            <div>
              {Array.from({ length: 6 }, (_, i) => (
                <div key={i} style={skeletonRowStyle}>
                  <Skeleton style={{ width: 20, height: 20, borderRadius: 'var(--ts-radius-sm)' }} />
                  <Skeleton style={{ width: 80, height: 14 }} />
                  <Skeleton style={{ width: 160, height: 12, flex: 1 }} />
                  <Skeleton style={{ width: 60, height: 12 }} />
                </div>
              ))}
            </div>
          ) : displayItems.length === 0 ? (
            <div style={emptyStateStyle} data-ts-symbol-search-empty="">
              {query.length > 0 ? 'No results found' : 'Type to search symbols'}
            </div>
          ) : (
            <div style={scrollResultsStyle}>
              <ScrollArea>
                {showRecentsLabel && (
                  <div style={sectionLabelStyle}>Recent searches</div>
                )}
                {displayItems.map((item, index) => renderResultItem(item, index))}
              </ScrollArea>
            </div>
          )}
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

SymbolSearchDialog.displayName = 'SymbolSearchDialog';
