import { useCallback, type CSSProperties, type MouseEventHandler } from 'react';
import { Pencil, Trash2, Bell, BellOff } from 'lucide-react';
import { formatPrice } from './format-number';

/* -------------------------------------------------------------------------- */
/*  AlertRow                                                                  */
/*  Alert entry showing condition, status, and action buttons.                */
/*  Uses --ts-alert-row-* tokens.                                             */
/* -------------------------------------------------------------------------- */

type AlertStatus = 'active' | 'triggered' | 'disabled';

export interface AlertRowProps {
  /** Symbol this alert is for. */
  symbol: string;
  /** Human-readable condition description. */
  condition: string;
  /** Price level for the alert. */
  price: number;
  /** Current alert status. */
  status: AlertStatus;
  /** Decimal places for price display. */
  precision?: number;
  /** Called when the edit action is triggered. */
  onEdit?: MouseEventHandler<HTMLButtonElement>;
  /** Called when the delete action is triggered. */
  onDelete?: MouseEventHandler<HTMLButtonElement>;
  /** Called when the toggle action is triggered. */
  onToggle?: MouseEventHandler<HTMLButtonElement>;
}

/* ----- Style injection for hover actions --------------------------------- */

const ALERT_STYLE_ID = 'ts-alert-row-styles';

function ensureAlertStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(ALERT_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = ALERT_STYLE_ID;
  sheet.textContent = `
    [data-ts-alert-row]:hover {
      background: var(--ts-alert-row-bg-hover);
    }
    [data-ts-alert-row] [data-ts-alert-actions] {
      opacity: 0.6;
      transition: opacity 150ms;
    }
    [data-ts-alert-row]:hover [data-ts-alert-actions],
    [data-ts-alert-row]:focus-within [data-ts-alert-actions] {
      opacity: 1;
    }
    [data-ts-alert-action]:hover {
      color: var(--ts-text-primary);
    }
    [data-ts-alert-action]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 1px;
      border-radius: var(--ts-radius-sm);
    }
    [data-ts-alert-action][data-danger]:hover {
      color: var(--ts-status-error);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAlertStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-alert-row-height)',
  padding: `0 var(--ts-alert-row-padding-x)`,
  background: 'var(--ts-alert-row-bg)',
  borderBottom: '1px solid var(--ts-alert-row-border)',
  transition: 'background 100ms',
  boxSizing: 'border-box',
};

const STATUS_INDICATOR_COLOR: Record<AlertStatus, string> = {
  active: 'var(--ts-alert-row-active-indicator)',
  triggered: 'var(--ts-alert-row-triggered-indicator)',
  disabled: 'var(--ts-alert-row-disabled-indicator)',
};

const indicatorBaseStyle: CSSProperties = {
  width: 8,
  height: 8,
  borderRadius: '50%',
  flexShrink: 0,
  marginRight: 'var(--ts-space-2)',
};

const infoColumnStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  flex: 1,
  minWidth: 0,
  overflow: 'hidden',
};

const symbolTextStyle: CSSProperties = {
  color: 'var(--ts-alert-row-symbol-text)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  fontSize: 'var(--ts-font-sm)',
  lineHeight: 1.2,
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
};

const conditionTextStyle: CSSProperties = {
  color: 'var(--ts-alert-row-condition-text)',
  fontSize: 'var(--ts-font-xs)',
  lineHeight: 1.2,
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
};

const priceStyle: CSSProperties = {
  fontFamily: 'var(--ts-alert-row-price-font)',
  fontSize: 'var(--ts-font-sm)',
  fontVariantNumeric: 'tabular-nums',
  color: 'var(--ts-text-primary)',
  textAlign: 'right',
  padding: '0 var(--ts-space-2)',
  whiteSpace: 'nowrap',
};

const actionsStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
};

const actionButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 24,
  height: 24,
  cursor: 'pointer',
  color: 'var(--ts-text-secondary)',
  borderRadius: 'var(--ts-radius-sm)',
  transition: 'color 150ms',
};

/* ----- Component --------------------------------------------------------- */

export function AlertRow({
  symbol,
  condition,
  price,
  status,
  precision = 2,
  onEdit,
  onDelete,
  onToggle,
}: AlertRowProps): React.JSX.Element {
  const indicatorStyle: CSSProperties = {
    ...indicatorBaseStyle,
    background: STATUS_INDICATOR_COLOR[status],
  };

  const stopPropagation = useCallback(
    (handler: MouseEventHandler<HTMLButtonElement> | undefined) =>
      (e: React.MouseEvent<HTMLButtonElement>): void => {
        e.stopPropagation();
        handler?.(e);
      },
    [],
  );

  const isDisabled = status === 'disabled';
  const ToggleIcon = isDisabled ? BellOff : Bell;
  const toggleLabel = isDisabled ? 'Enable alert' : 'Disable alert';

  return (
    <div
      data-ts-alert-row=""
      data-status={status}
      style={rowStyle}
      role="row"
      data-testid="alert-row"
    >
      <div style={indicatorStyle} aria-label={`Status: ${status}`} data-testid="alert-status" />
      <div style={infoColumnStyle}>
        <span style={symbolTextStyle}>{symbol}</span>
        <span style={conditionTextStyle} title={condition}>{condition}</span>
      </div>
      <span className="ts-data-value" style={priceStyle} data-testid="alert-price">
        {formatPrice(price, precision)}
      </span>
      <div data-ts-alert-actions="" style={actionsStyle}>
        {onToggle !== undefined && (
          <button
            type="button"
            data-ts-alert-action=""
            style={actionButtonStyle}
            onClick={stopPropagation(onToggle)}
            aria-label={toggleLabel}
            data-testid="alert-toggle"
          >
            <ToggleIcon size={14} aria-hidden="true" />
          </button>
        )}
        {onEdit !== undefined && (
          <button
            type="button"
            data-ts-alert-action=""
            style={actionButtonStyle}
            onClick={stopPropagation(onEdit)}
            aria-label="Edit alert"
            data-testid="alert-edit"
          >
            <Pencil size={14} aria-hidden="true" />
          </button>
        )}
        {onDelete !== undefined && (
          <button
            type="button"
            data-ts-alert-action=""
            data-danger=""
            style={actionButtonStyle}
            onClick={stopPropagation(onDelete)}
            aria-label="Delete alert"
            data-testid="alert-delete"
          >
            <Trash2 size={14} aria-hidden="true" />
          </button>
        )}
      </div>
    </div>
  );
}

AlertRow.displayName = 'AlertRow';
