import { forwardRef, useCallback, type ReactNode } from 'react';
import { LineChart, Bell, BarChart2, FolderInput, Copy, Trash2, Send, TrendingUp, Search } from 'lucide-react';
import { ContextMenu } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  WatchlistContextMenu                                                       */
/*  Right-click context menu for watchlist rows with common actions.            */
/*  Composes ContextMenu from Phase 0 primitives.                              */
/* -------------------------------------------------------------------------- */

export interface WatchlistContextMenuProps {
  /** The symbol this context menu targets. */
  symbol: string;
  /** The trigger element (typically a WatchlistRow). */
  children: ReactNode;
  /** Called when "Open Chart" is selected. */
  onViewChart: (symbol: string) => void;
  /** Called when "Add Alert" is selected. */
  onAddAlert: (symbol: string) => void;
  /** Called when "View Depth" is selected. */
  onViewDepth: (symbol: string) => void;
  /** Called when "Remove" is selected. */
  onRemove: (symbol: string) => void;
  /** Available sections for "Move to" submenu. */
  sections: string[];
  /** Called when a "Move to" section is selected. */
  onMoveToSection: (symbol: string, section: string) => void;
  /** Called when "Copy Symbol" is selected. */
  onCopySymbol: (symbol: string) => void;
  /** Called when "Send to Analytics" is selected. */
  onSendToAnalytics?: (symbolId: string) => void;
  /** Called when "Send to Screener" is selected. */
  onSendToScreener?: (symbolId: string) => void;
}

/* ----- Component --------------------------------------------------------- */

export const WatchlistContextMenu = forwardRef<HTMLDivElement, WatchlistContextMenuProps>(function WatchlistContextMenu({
  symbol,
  children,
  onViewChart,
  onAddAlert,
  onViewDepth,
  onRemove,
  sections,
  onMoveToSection,
  onCopySymbol,
  onSendToAnalytics,
  onSendToScreener,
}, _ref) {
  const handleViewChart = useCallback(() => {
    onViewChart(symbol);
  }, [onViewChart, symbol]);

  const handleAddAlert = useCallback(() => {
    onAddAlert(symbol);
  }, [onAddAlert, symbol]);

  const handleViewDepth = useCallback(() => {
    onViewDepth(symbol);
  }, [onViewDepth, symbol]);

  const handleRemove = useCallback(() => {
    onRemove(symbol);
  }, [onRemove, symbol]);

  const handleCopySymbol = useCallback(() => {
    onCopySymbol(symbol);
  }, [onCopySymbol, symbol]);

  const handleSendToAnalytics = useCallback(() => {
    onSendToAnalytics?.(symbol);
  }, [onSendToAnalytics, symbol]);

  const handleSendToScreener = useCallback(() => {
    onSendToScreener?.(symbol);
  }, [onSendToScreener, symbol]);

  const handleMoveToSection = useCallback(
    (section: string) => {
      onMoveToSection(symbol, section);
    },
    [onMoveToSection, symbol],
  );

  return (
    <ContextMenu data-ts-watchlist-context-menu="">
      <ContextMenu.Trigger>
        <div data-testid="watchlist-context-trigger">{children}</div>
      </ContextMenu.Trigger>
      <ContextMenu.Content data-testid="watchlist-context-menu">
        <ContextMenu.Item
          icon={<LineChart size={14} />}
          onSelect={handleViewChart}
          data-testid="watchlist-ctx-open-chart"
        >
          Open Chart
        </ContextMenu.Item>
        <ContextMenu.Separator />
        <ContextMenu.Item
          icon={<Bell size={14} />}
          onSelect={handleAddAlert}
          data-testid="watchlist-ctx-add-alert"
        >
          Add Alert...
        </ContextMenu.Item>
        <ContextMenu.Separator />
        <ContextMenu.Item
          icon={<BarChart2 size={14} />}
          onSelect={handleViewDepth}
          data-testid="watchlist-ctx-view-depth"
        >
          View Depth
        </ContextMenu.Item>
        <ContextMenu.Separator />
        <ContextMenu.Sub>
          <ContextMenu.SubTrigger
            icon={<Send size={14} />}
            data-testid="watchlist-ctx-send-to"
          >
            Send to...
          </ContextMenu.SubTrigger>
          <ContextMenu.SubContent>
            <ContextMenu.Item
              icon={<LineChart size={14} />}
              onSelect={handleViewChart}
              data-testid="watchlist-ctx-send-chart"
            >
              Chart
            </ContextMenu.Item>
            <ContextMenu.Item
              icon={<BarChart2 size={14} />}
              onSelect={handleViewDepth}
              data-testid="watchlist-ctx-send-depth"
            >
              Depth
            </ContextMenu.Item>
            {onSendToAnalytics && (
              <ContextMenu.Item
                icon={<TrendingUp size={14} />}
                onSelect={handleSendToAnalytics}
                data-testid="watchlist-ctx-send-analytics"
              >
                Analytics
              </ContextMenu.Item>
            )}
            {onSendToScreener && (
              <ContextMenu.Item
                icon={<Search size={14} />}
                onSelect={handleSendToScreener}
                data-testid="watchlist-ctx-send-screener"
              >
                Screener
              </ContextMenu.Item>
            )}
          </ContextMenu.SubContent>
        </ContextMenu.Sub>
        <ContextMenu.Separator />
        <ContextMenu.Sub>
          <ContextMenu.SubTrigger
            icon={<FolderInput size={14} />}
            data-testid="watchlist-ctx-move-to"
          >
            Move to
          </ContextMenu.SubTrigger>
          <ContextMenu.SubContent>
            {sections.map((section) => (
              <ContextMenu.Item
                key={section}
                onSelect={() => handleMoveToSection(section)}
                data-testid={`watchlist-ctx-move-${section}`}
              >
                {section}
              </ContextMenu.Item>
            ))}
          </ContextMenu.SubContent>
        </ContextMenu.Sub>
        <ContextMenu.Separator />
        <ContextMenu.Item
          icon={<Copy size={14} />}
          onSelect={handleCopySymbol}
          data-testid="watchlist-ctx-copy"
        >
          Copy Symbol
        </ContextMenu.Item>
        <ContextMenu.Separator />
        <ContextMenu.Item
          icon={<Trash2 size={14} />}
          danger
          onSelect={handleRemove}
          data-testid="watchlist-ctx-remove"
        >
          Remove
        </ContextMenu.Item>
      </ContextMenu.Content>
    </ContextMenu>
  );
});
