import { useCallback, type CSSProperties } from 'react';
import { DropdownMenu, Tooltip } from '../primitives';
import { ChevronDown, Plus, Star } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  TimeframeBar                                                              */
/*  Quick-access timeframe buttons + dropdown with grouped timeframe list.    */
/*  Uses --ts-selector-* tokens.                                              */
/* -------------------------------------------------------------------------- */

export interface Timeframe {
  /** Display label, e.g. "1m", "5m", "1H", "4H", "1D", "1W", "1M". */
  label: string;
  /** Unique value identifier. */
  value: string;
  /** Whether this is a user-favorited timeframe. */
  favorite?: boolean;
}

export interface TimeframeGroup {
  /** Group label (e.g., "Minutes", "Hours", "Days"). */
  label: string;
  /** Timeframes in this group. */
  items: Timeframe[];
}

export interface TimeframeBarProps {
  /** Available timeframes to show as quick-access buttons. */
  timeframes: Timeframe[];
  /** Currently selected timeframe value. */
  value: string;
  /** Called when a timeframe is selected. */
  onValueChange: (value: string) => void;
  /** Called when the dropdown trigger is clicked (opens full timeframe list). */
  onDropdownOpen?: () => void;
  /** Called when "Add custom interval" is clicked. */
  onCustomIntervalClick?: () => void;
  /** Grouped timeframes for the dropdown. */
  dropdownGroups?: TimeframeGroup[];
  /** Whether the dropdown is currently open. */
  dropdownOpen?: boolean;
  /** Called when the dropdown open state changes. */
  onDropdownOpenChange?: (open: boolean) => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-timeframe-bar-styles';

function ensureTimeframeBarStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-timeframe-button]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 1px;
    }
    [data-ts-timeframe-button]:not(:disabled):not([data-active]):hover {
      color: var(--ts-selector-inactive-text-hover);
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-timeframe-button]:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
    [data-ts-timeframe-dropdown-trigger]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 1px;
    }
    [data-ts-timeframe-dropdown-trigger]:hover {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-timeframe-favorite-star] {
      opacity: 0.4;
      transition: opacity 100ms;
    }
    [data-ts-timeframe-favorite-star]:hover {
      opacity: 1;
    }
    [data-ts-timeframe-favorite-star][data-favorite] {
      opacity: 1;
      color: var(--ts-accent-default);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTimeframeBarStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '2px',
  flexShrink: 0,
};

const buttonBaseStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: 'var(--ts-selector-height)',
  padding: '0 var(--ts-selector-padding-x)',
  fontSize: 'var(--ts-selector-font-size)',
  fontWeight: 'var(--ts-selector-font-weight)' as unknown as number,
  fontFamily: 'inherit',
  lineHeight: 1,
  whiteSpace: 'nowrap',
  borderRadius: 'var(--ts-selector-radius)',
  cursor: 'pointer',
  userSelect: 'none',
  boxSizing: 'border-box',
  transition: 'background 150ms, color 150ms',
};

const activeButtonStyle: CSSProperties = {
  ...buttonBaseStyle,
  background: 'var(--ts-selector-active-bg)',
  color: 'var(--ts-selector-active-text)',
};

const inactiveButtonStyle: CSSProperties = {
  ...buttonBaseStyle,
  background: 'transparent',
  color: 'var(--ts-selector-inactive-text)',
};

const dropdownTriggerStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-selector-height)',
  height: 'var(--ts-selector-height)',
  borderRadius: 'var(--ts-selector-radius)',
  cursor: 'pointer',
  color: 'var(--ts-selector-inactive-text)',
  transition: 'background 150ms',
  boxSizing: 'border-box',
};

/* ----- Component --------------------------------------------------------- */

export function TimeframeBar({
  timeframes,
  value,
  onValueChange,
  onCustomIntervalClick,
  dropdownGroups,
  dropdownOpen,
  onDropdownOpenChange,
}: TimeframeBarProps): React.JSX.Element {
  const handleSelect = useCallback(
    (tfValue: string) => {
      onValueChange(tfValue);
    },
    [onValueChange],
  );

  const hasDropdown = dropdownGroups !== undefined && dropdownGroups.length > 0;

  return (
    <div data-ts-timeframe-bar="" style={containerStyle}>
      {timeframes.map((tf) => {
        const isActive = tf.value === value;
        return (
          <Tooltip key={tf.value} content={tf.label} side="bottom" delayDuration={600}>
            <button
              type="button"
              data-ts-timeframe-button=""
              {...(isActive ? { 'data-active': '' } : {})}
              style={isActive ? activeButtonStyle : inactiveButtonStyle}
              aria-label={`Timeframe ${tf.label}`}
              aria-pressed={isActive}
              onClick={() => handleSelect(tf.value)}
            >
              {tf.label}
            </button>
          </Tooltip>
        );
      })}

      {hasDropdown && (
        <DropdownMenu
          open={dropdownOpen}
          onOpenChange={onDropdownOpenChange}
        >
          <DropdownMenu.Trigger>
            <button
              type="button"
              data-ts-timeframe-dropdown-trigger=""
              aria-label="More timeframes"
              style={dropdownTriggerStyle}
            >
              <ChevronDown size={14} />
            </button>
          </DropdownMenu.Trigger>
          <DropdownMenu.Content align="start" style={{ minWidth: 200 }}>
            {onCustomIntervalClick !== undefined && (
              <>
                <DropdownMenu.Item
                  icon={<Plus size={14} />}
                  onSelect={onCustomIntervalClick}
                >
                  Add custom interval...
                </DropdownMenu.Item>
                <DropdownMenu.Separator />
              </>
            )}
            {dropdownGroups.map((group, gi) => (
              <div key={group.label}>
                {gi > 0 && <DropdownMenu.Separator />}
                <DropdownMenu.Label>{group.label}</DropdownMenu.Label>
                {group.items.map((item) => (
                  <DropdownMenu.Item
                    key={item.value}
                    onSelect={() => handleSelect(item.value)}
                  >
                    <span style={{ flex: 1 }}>{item.label}</span>
                    {item.favorite !== undefined && (
                      <Star
                        size={12}
                        data-ts-timeframe-favorite-star=""
                        {...(item.favorite ? { 'data-favorite': '' } : {})}
                        fill={item.favorite ? 'currentColor' : 'none'}
                      />
                    )}
                  </DropdownMenu.Item>
                ))}
              </div>
            ))}
          </DropdownMenu.Content>
        </DropdownMenu>
      )}
    </div>
  );
}

TimeframeBar.displayName = 'TimeframeBar';
