import type { CSSProperties, MouseEventHandler } from 'react';
import { formatPrice } from './format-number';
import { Tag } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  WatchlistRow                                                              */
/*  Single row in a watchlist showing symbol, price, and change.              */
/*  Uses --ts-watchlist-* and --ts-price-change-* tokens.                     */
/* -------------------------------------------------------------------------- */

export interface WatchlistRowProps {
  /** Ticker symbol, e.g. "BTCUSDT". */
  symbol: string;
  /** Exchange name, e.g. "Binance". */
  exchange: string;
  /** Current price (null = awaiting data). */
  price: number | null;
  /** Absolute price change (null = awaiting data). */
  priceChange: number | null;
  /** Percentage price change (null = awaiting data). */
  priceChangePercent: number | null;
  /** Decimal places for price display. */
  precision?: number;
  /** Whether this row is selected. */
  selected?: boolean;
  /** Whether the symbol's data is stale. */
  stale?: boolean;
  /** Click handler. */
  onClick?: MouseEventHandler<HTMLDivElement>;
}

/* ----- Style injection for hover ----------------------------------------- */

const ROW_STYLE_ID = 'ts-watchlist-row-styles';

function ensureRowStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(ROW_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = ROW_STYLE_ID;
  sheet.textContent = `
    [data-ts-watchlist-row]:hover:not([data-selected]) {
      background: var(--ts-watchlist-row-bg-hover);
    }
    [data-ts-watchlist-row]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureRowStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rowBaseStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-watchlist-row-height)',
  padding: `0 var(--ts-watchlist-row-padding-x)`,
  background: 'var(--ts-watchlist-row-bg)',
  borderBottom: '1px solid var(--ts-watchlist-row-border)',
  cursor: 'pointer',
  userSelect: 'none',
  transition: 'background 100ms',
  boxSizing: 'border-box',
};

const rowSelectedStyle: CSSProperties = {
  ...rowBaseStyle,
  background: 'var(--ts-watchlist-row-bg-selected)',
};

const symbolColumnStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  flex: 1,
  minWidth: 0,
  overflow: 'hidden',
};

const symbolTextStyle: CSSProperties = {
  color: 'var(--ts-watchlist-symbol-text)',
  fontWeight: 'var(--ts-watchlist-symbol-font-weight)' as unknown as number,
  fontSize: 'var(--ts-font-sm)',
  lineHeight: 1.2,
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
};

const exchangeTextStyle: CSSProperties = {
  color: 'var(--ts-watchlist-exchange-text)',
  fontSize: 'var(--ts-watchlist-exchange-font-size)',
  lineHeight: 1.2,
};

const priceColumnStyle: CSSProperties = {
  fontFamily: 'var(--ts-watchlist-price-font)',
  fontSize: 'var(--ts-font-sm)',
  fontVariantNumeric: 'tabular-nums',
  color: 'var(--ts-text-primary)',
  textAlign: 'right',
  padding: '0 var(--ts-space-2)',
  whiteSpace: 'nowrap',
};

const changeColumnBaseStyle: CSSProperties = {
  fontFamily: 'var(--ts-watchlist-price-font)',
  fontSize: 'var(--ts-font-sm)',
  fontVariantNumeric: 'tabular-nums',
  textAlign: 'right',
  minWidth: '72px',
  whiteSpace: 'nowrap',
};

/* ----- Direction helpers ------------------------------------------------- */

type Direction = 'up' | 'down' | 'neutral';

function getDirection(value: number | null): Direction {
  if (value == null) return 'neutral';
  if (value > 0) return 'up';
  if (value < 0) return 'down';
  return 'neutral';
}

const DIRECTION_COLOR: Record<Direction, string> = {
  up: 'var(--ts-price-change-up-text)',
  down: 'var(--ts-price-change-down-text)',
  neutral: 'var(--ts-price-neutral-text)',
};

/* ----- Component --------------------------------------------------------- */

const stalePriceStyle: CSSProperties = {
  ...priceColumnStyle,
  color: 'var(--ts-text-disabled, #6b7280)',
};

const staleTagContainerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  marginLeft: 'var(--ts-space-1, 4px)',
  flexShrink: 0,
};

export function WatchlistRow({
  symbol,
  exchange,
  price,
  priceChange,
  priceChangePercent,
  precision = 2,
  selected = false,
  stale = false,
  onClick,
}: WatchlistRowProps): React.JSX.Element {
  const hasData = price != null;
  const direction = getDirection(priceChange);
  const sign = (priceChange ?? 0) > 0 ? '+' : '';

  const changeStyle: CSSProperties = {
    ...changeColumnBaseStyle,
    color: stale ? 'var(--ts-text-disabled, #6b7280)' : DIRECTION_COLOR[direction],
  };

  return (
    <div
      data-ts-watchlist-row=""
      {...(selected ? { 'data-selected': '' } : {})}
      {...(stale ? { 'data-stale': '' } : {})}
      style={selected ? rowSelectedStyle : rowBaseStyle}
      onClick={onClick}
      role="row"
      tabIndex={0}
      data-testid="watchlist-row"
    >
      <div style={symbolColumnStyle}>
        <span style={symbolTextStyle}>{symbol}</span>
        <span style={exchangeTextStyle}>{exchange}</span>
      </div>
      <span className="ts-data-value" style={stale ? stalePriceStyle : priceColumnStyle} data-testid="watchlist-price">
        {hasData ? formatPrice(price, precision) : '--'}
      </span>
      {stale && (
        <span style={staleTagContainerStyle} data-testid="watchlist-stale-tag">
          <Tag>stale</Tag>
        </span>
      )}
      <span className="ts-data-value" style={changeStyle} data-direction={direction} data-testid="watchlist-change">
        {priceChangePercent != null ? `${sign}${priceChangePercent.toFixed(2)}%` : '--'}
      </span>
    </div>
  );
}

WatchlistRow.displayName = 'WatchlistRow';
