import { forwardRef, type CSSProperties, type ReactNode, type ElementRef, type ComponentPropsWithoutRef } from 'react';
import { Popover as PopoverPrimitive } from 'radix-ui';

/* -------------------------------------------------------------------------- */
/*  Popover                                                                   */
/*  Floating content panel anchored to a trigger.                             */
/*  Wraps Radix Popover — uses --ts-overlay-* tokens.                         */
/* -------------------------------------------------------------------------- */

/* ----- Style injection for animations ------------------------------------ */

const POPOVER_STYLE_ID = 'ts-popover-styles';

function ensurePopoverStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(POPOVER_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = POPOVER_STYLE_ID;
  sheet.textContent = `
    @keyframes ts-popover-fade-in {
      from { opacity: 0; transform: translateY(2px) scale(0.98); }
      to { opacity: 1; transform: translateY(0) scale(1); }
    }
    @keyframes ts-popover-fade-out {
      from { opacity: 1; transform: translateY(0) scale(1); }
      to { opacity: 0; transform: translateY(2px) scale(0.98); }
    }
    [data-ts-popover-content][data-state="open"] {
      animation: ts-popover-fade-in 150ms ease-out;
    }
    [data-ts-popover-content][data-state="closed"] {
      animation: ts-popover-fade-out 100ms ease-in;
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-popover-content][data-state="open"],
      [data-ts-popover-content][data-state="closed"] {
        animation: none;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensurePopoverStyles();
}

/* ----- Popover.Root ------------------------------------------------------ */

type PopoverRootProps = ComponentPropsWithoutRef<typeof PopoverPrimitive.Root>;

function Root(props: PopoverRootProps): React.JSX.Element {
  return <PopoverPrimitive.Root {...props} />;
}
Root.displayName = 'Popover';

/* ----- Popover.Trigger --------------------------------------------------- */

type PopoverTriggerProps = ComponentPropsWithoutRef<typeof PopoverPrimitive.Trigger>;

const PopoverTrigger = forwardRef<ElementRef<typeof PopoverPrimitive.Trigger>, PopoverTriggerProps>(
  (props, ref) => <PopoverPrimitive.Trigger ref={ref} asChild {...props} />,
);
PopoverTrigger.displayName = 'Popover.Trigger';

/* ----- Popover.Content --------------------------------------------------- */

const popoverContentStyle: CSSProperties = {
  background: 'var(--ts-overlay-bg)',
  border: '1px solid var(--ts-overlay-border)',
  borderRadius: 'var(--ts-overlay-radius)',
  boxShadow: 'var(--ts-overlay-shadow)',
  zIndex: 50,
  outline: 'none',
  boxSizing: 'border-box',
  fontFamily: 'inherit',
};

type PopoverContentProps = ComponentPropsWithoutRef<typeof PopoverPrimitive.Content> & {
  /** Popover content. */
  children: ReactNode;
};

const PopoverContent = forwardRef<ElementRef<typeof PopoverPrimitive.Content>, PopoverContentProps>(
  ({ style, side = 'bottom', align = 'center', sideOffset = 4, ...props }, ref) => (
    <PopoverPrimitive.Portal>
      <PopoverPrimitive.Content
        ref={ref}
        data-ts-popover-content=""
        side={side}
        align={align}
        sideOffset={sideOffset}
        style={{ ...popoverContentStyle, ...style }}
        {...props}
      />
    </PopoverPrimitive.Portal>
  ),
);
PopoverContent.displayName = 'Popover.Content';

/* ----- Compound export --------------------------------------------------- */

export const Popover = Object.assign(Root, {
  Root,
  Trigger: PopoverTrigger,
  Content: PopoverContent,
});
