import { useState, useEffect } from "react";
import type { DesktopAgent } from "../fdc3-types";

/**
 * Hook providing FDC3 API availability and readiness state.
 *
 * Returns null if FDC3 is not available (app not running in a Desktop Agent).
 * Returns the DesktopAgent API object when ready.
 *
 * The hook listens for the `fdc3Ready` event on `window` and checks
 * `window.fdc3` on mount. Once resolved, the reference is stable and
 * does not cause re-renders.
 *
 * Usage:
 *   const fdc3 = useFdc3();
 *   if (!fdc3) return <div>Requires FDC3 Desktop Agent</div>;
 */
export function useFdc3(): DesktopAgent | null {
  const [agent, setAgent] = useState<DesktopAgent | null>(() => {
    if (typeof window !== "undefined" && window.fdc3) {
      return window.fdc3;
    }
    return null;
  });

  useEffect(() => {
    // Already resolved — no listener needed
    if (agent) {
      return;
    }

    // Check again in case it was set between render and effect
    if (window.fdc3) {
      setAgent(window.fdc3);
      return;
    }

    function onFdc3Ready(): void {
      if (window.fdc3) {
        setAgent(window.fdc3);
      }
    }

    window.addEventListener("fdc3Ready", onFdc3Ready);

    return () => {
      window.removeEventListener("fdc3Ready", onFdc3Ready);
    };
  }, [agent]);

  return agent;
}
