import { forwardRef, type CSSProperties, type ReactNode, type ElementRef, type ComponentPropsWithoutRef } from 'react';
import { DropdownMenu as DropdownMenuPrimitive } from 'radix-ui';
import { ChevronRight, Check, Circle } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  DropdownMenu                                                              */
/*  Click-triggered dropdown menu with items, checkboxes, radios, submenus.   */
/*  Wraps Radix DropdownMenu — uses --ts-menu-* and --ts-overlay-* tokens.    */
/* -------------------------------------------------------------------------- */

/* ----- Style injection --------------------------------------------------- */

const DROPDOWN_MENU_STYLE_ID = 'ts-dropdown-menu-styles';

function ensureDropdownMenuStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(DROPDOWN_MENU_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = DROPDOWN_MENU_STYLE_ID;
  sheet.textContent = `
    @keyframes ts-dropdown-menu-fade-in {
      from { opacity: 0; transform: translateY(-2px) scale(0.98); }
      to { opacity: 1; transform: translateY(0) scale(1); }
    }
    [data-ts-dropdown-menu-content][data-state="open"] {
      animation: ts-dropdown-menu-fade-in 120ms ease-out;
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-dropdown-menu-content][data-state="open"] {
        animation: none;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureDropdownMenuStyles();
}

/* ----- Shared styles ----------------------------------------------------- */

const menuContentStyle: CSSProperties = {
  background: 'var(--ts-overlay-bg)',
  border: '1px solid var(--ts-overlay-border)',
  borderRadius: 'var(--ts-overlay-radius)',
  boxShadow: 'var(--ts-overlay-shadow)',
  padding: 'var(--ts-menu-padding-y) 0',
  minWidth: 180,
  maxHeight: 'min(max(280px, 70vh), calc(100vh - 40px))',
  overflowY: 'auto',
  zIndex: 50,
  outline: 'none',
  boxSizing: 'border-box',
  fontFamily: 'inherit',
};

const menuItemStyle: CSSProperties = {
  all: 'unset',
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-menu-item-height)',
  padding: '0 var(--ts-menu-item-padding-x)',
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
  color: 'var(--ts-menu-item-text)',
  cursor: 'pointer',
  userSelect: 'none',
  gap: '8px',
  boxSizing: 'border-box',
  transition: 'background 100ms',
};

const menuItemDangerStyle: CSSProperties = {
  ...menuItemStyle,
  color: 'var(--ts-menu-item-text-danger)',
};

const separatorStyle: CSSProperties = {
  height: 1,
  background: 'var(--ts-menu-separator)',
  margin: 'var(--ts-menu-separator-margin) 0',
};

const labelStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-menu-item-height)',
  padding: '0 var(--ts-menu-item-padding-x)',
  fontSize: 'var(--ts-menu-label-font-size)',
  fontWeight: 'var(--ts-menu-label-font-weight)' as unknown as number,
  fontFamily: 'inherit',
  color: 'var(--ts-menu-label-text)',
  userSelect: 'none',
  boxSizing: 'border-box',
};

const iconSlotStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 16,
  height: 16,
  flexShrink: 0,
  color: 'var(--ts-menu-item-icon)',
};

const shortcutSlotStyle: CSSProperties = {
  marginLeft: 'auto',
  paddingLeft: '16px',
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-menu-item-shortcut)',
  fontFamily: 'inherit',
};

const subTriggerArrowStyle: CSSProperties = {
  marginLeft: 'auto',
  color: 'var(--ts-menu-item-shortcut)',
};

const indicatorStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 16,
  height: 16,
  flexShrink: 0,
};

/* ----- Hover handler factory --------------------------------------------- */

function handleItemHover(e: React.MouseEvent<HTMLDivElement>): void {
  e.currentTarget.style.background = 'var(--ts-menu-item-bg-hover)';
}

function handleItemUnhover(e: React.MouseEvent<HTMLDivElement>): void {
  e.currentTarget.style.background = 'transparent';
}

/* ----- DropdownMenu.Root ------------------------------------------------- */

type DropdownMenuRootProps = ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.Root>;

function Root(props: DropdownMenuRootProps): React.JSX.Element {
  return <DropdownMenuPrimitive.Root {...props} />;
}
Root.displayName = 'DropdownMenu';

/* ----- DropdownMenu.Trigger ---------------------------------------------- */

type DropdownMenuTriggerProps = ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.Trigger>;

const DropdownMenuTrigger = forwardRef<ElementRef<typeof DropdownMenuPrimitive.Trigger>, DropdownMenuTriggerProps>(
  (props, ref) => <DropdownMenuPrimitive.Trigger ref={ref} asChild {...props} />,
);
DropdownMenuTrigger.displayName = 'DropdownMenu.Trigger';

/* ----- DropdownMenu.Content ---------------------------------------------- */

type DropdownMenuContentProps = ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.Content>;

const DropdownMenuContent = forwardRef<ElementRef<typeof DropdownMenuPrimitive.Content>, DropdownMenuContentProps>(
  ({ style, sideOffset = 4, ...props }, ref) => (
    <DropdownMenuPrimitive.Portal>
      <DropdownMenuPrimitive.Content
        ref={ref}
        data-ts-dropdown-menu-content=""
        sideOffset={sideOffset}
        style={{ ...menuContentStyle, ...style }}
        {...props}
      />
    </DropdownMenuPrimitive.Portal>
  ),
);
DropdownMenuContent.displayName = 'DropdownMenu.Content';

/* ----- DropdownMenu.Item ------------------------------------------------- */

interface DropdownMenuItemProps extends ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.Item> {
  /** Icon element rendered before the label. */
  icon?: ReactNode;
  /** Keyboard shortcut text rendered at the right edge. */
  shortcut?: string;
  /** Danger variant for destructive actions. */
  danger?: boolean;
}

const DropdownMenuItem = forwardRef<ElementRef<typeof DropdownMenuPrimitive.Item>, DropdownMenuItemProps>(
  ({ icon, shortcut, danger, children, style, onMouseEnter, onMouseLeave, ...props }, ref) => (
    <DropdownMenuPrimitive.Item
      ref={ref}
      style={{ ...(danger ? menuItemDangerStyle : menuItemStyle), ...style }}
      onMouseEnter={(e) => {
        handleItemHover(e);
        onMouseEnter?.(e);
      }}
      onMouseLeave={(e) => {
        handleItemUnhover(e);
        onMouseLeave?.(e);
      }}
      {...props}
    >
      {icon ? <span style={iconSlotStyle}>{icon}</span> : null}
      <span style={{ flex: 1 }}>{children}</span>
      {shortcut ? <span style={shortcutSlotStyle}>{shortcut}</span> : null}
    </DropdownMenuPrimitive.Item>
  ),
);
DropdownMenuItem.displayName = 'DropdownMenu.Item';

/* ----- DropdownMenu.CheckboxItem ----------------------------------------- */

interface DropdownMenuCheckboxItemProps extends ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.CheckboxItem> {
  /** Keyboard shortcut text rendered at the right edge. */
  shortcut?: string;
}

const DropdownMenuCheckboxItem = forwardRef<ElementRef<typeof DropdownMenuPrimitive.CheckboxItem>, DropdownMenuCheckboxItemProps>(
  ({ shortcut, children, style, onMouseEnter, onMouseLeave, ...props }, ref) => (
    <DropdownMenuPrimitive.CheckboxItem
      ref={ref}
      style={{ ...menuItemStyle, ...style }}
      onMouseEnter={(e) => {
        handleItemHover(e);
        onMouseEnter?.(e);
      }}
      onMouseLeave={(e) => {
        handleItemUnhover(e);
        onMouseLeave?.(e);
      }}
      {...props}
    >
      <span style={indicatorStyle}>
        <DropdownMenuPrimitive.ItemIndicator>
          <Check size={14} />
        </DropdownMenuPrimitive.ItemIndicator>
      </span>
      <span style={{ flex: 1 }}>{children}</span>
      {shortcut ? <span style={shortcutSlotStyle}>{shortcut}</span> : null}
    </DropdownMenuPrimitive.CheckboxItem>
  ),
);
DropdownMenuCheckboxItem.displayName = 'DropdownMenu.CheckboxItem';

/* ----- DropdownMenu.RadioGroup ------------------------------------------- */

type DropdownMenuRadioGroupProps = ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.RadioGroup>;

const DropdownMenuRadioGroup = forwardRef<ElementRef<typeof DropdownMenuPrimitive.RadioGroup>, DropdownMenuRadioGroupProps>(
  (props, ref) => <DropdownMenuPrimitive.RadioGroup ref={ref} {...props} />,
);
DropdownMenuRadioGroup.displayName = 'DropdownMenu.RadioGroup';

/* ----- DropdownMenu.RadioItem -------------------------------------------- */

type DropdownMenuRadioItemProps = ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.RadioItem>;

const DropdownMenuRadioItem = forwardRef<ElementRef<typeof DropdownMenuPrimitive.RadioItem>, DropdownMenuRadioItemProps>(
  ({ children, style, onMouseEnter, onMouseLeave, ...props }, ref) => (
    <DropdownMenuPrimitive.RadioItem
      ref={ref}
      style={{ ...menuItemStyle, ...style }}
      onMouseEnter={(e) => {
        handleItemHover(e);
        onMouseEnter?.(e);
      }}
      onMouseLeave={(e) => {
        handleItemUnhover(e);
        onMouseLeave?.(e);
      }}
      {...props}
    >
      <span style={indicatorStyle}>
        <DropdownMenuPrimitive.ItemIndicator>
          <Circle size={8} fill="currentColor" />
        </DropdownMenuPrimitive.ItemIndicator>
      </span>
      <span style={{ flex: 1 }}>{children}</span>
    </DropdownMenuPrimitive.RadioItem>
  ),
);
DropdownMenuRadioItem.displayName = 'DropdownMenu.RadioItem';

/* ----- DropdownMenu.Separator -------------------------------------------- */

type DropdownMenuSeparatorProps = ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.Separator>;

const DropdownMenuSeparator = forwardRef<ElementRef<typeof DropdownMenuPrimitive.Separator>, DropdownMenuSeparatorProps>(
  ({ style, ...props }, ref) => (
    <DropdownMenuPrimitive.Separator
      ref={ref}
      style={{ ...separatorStyle, ...style }}
      {...props}
    />
  ),
);
DropdownMenuSeparator.displayName = 'DropdownMenu.Separator';

/* ----- DropdownMenu.Label ------------------------------------------------ */

type DropdownMenuLabelProps = ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.Label>;

const DropdownMenuLabel = forwardRef<ElementRef<typeof DropdownMenuPrimitive.Label>, DropdownMenuLabelProps>(
  ({ style, ...props }, ref) => (
    <DropdownMenuPrimitive.Label
      ref={ref}
      style={{ ...labelStyle, ...style }}
      {...props}
    />
  ),
);
DropdownMenuLabel.displayName = 'DropdownMenu.Label';

/* ----- DropdownMenu.Sub -------------------------------------------------- */

type DropdownMenuSubProps = ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.Sub>;

function DropdownMenuSub(props: DropdownMenuSubProps): React.JSX.Element {
  return <DropdownMenuPrimitive.Sub {...props} />;
}
DropdownMenuSub.displayName = 'DropdownMenu.Sub';

/* ----- DropdownMenu.SubTrigger ------------------------------------------- */

interface DropdownMenuSubTriggerProps extends ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.SubTrigger> {
  /** Icon element rendered before the label. */
  icon?: ReactNode;
}

const DropdownMenuSubTrigger = forwardRef<ElementRef<typeof DropdownMenuPrimitive.SubTrigger>, DropdownMenuSubTriggerProps>(
  ({ icon, children, style, onMouseEnter, onMouseLeave, ...props }, ref) => (
    <DropdownMenuPrimitive.SubTrigger
      ref={ref}
      style={{ ...menuItemStyle, ...style }}
      onMouseEnter={(e) => {
        handleItemHover(e);
        onMouseEnter?.(e);
      }}
      onMouseLeave={(e) => {
        handleItemUnhover(e);
        onMouseLeave?.(e);
      }}
      {...props}
    >
      {icon ? <span style={iconSlotStyle}>{icon}</span> : null}
      <span style={{ flex: 1 }}>{children}</span>
      <ChevronRight size={14} style={subTriggerArrowStyle} aria-hidden />
    </DropdownMenuPrimitive.SubTrigger>
  ),
);
DropdownMenuSubTrigger.displayName = 'DropdownMenu.SubTrigger';

/* ----- DropdownMenu.SubContent ------------------------------------------- */

type DropdownMenuSubContentProps = ComponentPropsWithoutRef<typeof DropdownMenuPrimitive.SubContent>;

const DropdownMenuSubContent = forwardRef<ElementRef<typeof DropdownMenuPrimitive.SubContent>, DropdownMenuSubContentProps>(
  ({ style, ...props }, ref) => (
    <DropdownMenuPrimitive.Portal>
      <DropdownMenuPrimitive.SubContent
        ref={ref}
        data-ts-dropdown-menu-content=""
        sideOffset={2}
        alignOffset={-4}
        style={{ ...menuContentStyle, ...style }}
        {...props}
      />
    </DropdownMenuPrimitive.Portal>
  ),
);
DropdownMenuSubContent.displayName = 'DropdownMenu.SubContent';

/* ----- Compound export --------------------------------------------------- */

export const DropdownMenu = Object.assign(Root, {
  Root,
  Trigger: DropdownMenuTrigger,
  Content: DropdownMenuContent,
  Item: DropdownMenuItem,
  CheckboxItem: DropdownMenuCheckboxItem,
  RadioGroup: DropdownMenuRadioGroup,
  RadioItem: DropdownMenuRadioItem,
  Separator: DropdownMenuSeparator,
  Label: DropdownMenuLabel,
  Sub: DropdownMenuSub,
  SubTrigger: DropdownMenuSubTrigger,
  SubContent: DropdownMenuSubContent,
});
