import { forwardRef, useState, type CSSProperties } from 'react';
import { IconButton } from '../primitives';
import { formatPrice } from '../financial';
import { Eye, EyeOff, Settings, Trash2 } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  StatusLineGroup                                                           */
/*  Single indicator legend row with color dot, name, values, action buttons. */
/*  Uses --ts-status-line-* tokens.                                           */
/* -------------------------------------------------------------------------- */

export interface StatusLineGroupProps {
  /** Indicator display name. */
  name: string;
  /** Color for the indicator label (matches plot line color). */
  color?: string;
  /** Key-value pairs to display (e.g., { "MA": 50123.45, "Signal": 49800.0 }). */
  values: Record<string, number>;
  /** Decimal precision for numeric values. */
  precision?: number;
  /** Whether the indicator is currently visible on the chart. */
  visible?: boolean;
  /** Called when the hide/show button is clicked. */
  onVisibilityToggle?: () => void;
  /** Called when the settings button is clicked. */
  onSettings?: () => void;
  /** Called when the remove button is clicked. */
  onRemove?: () => void;
}

/* ----- Style injection for hover/focus states ----------------------------- */

const STATUS_GROUP_STYLE_ID = 'ts-status-line-group-styles';

function ensureStatusLineGroupStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STATUS_GROUP_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STATUS_GROUP_STYLE_ID;
  sheet.textContent = `
    [data-ts-status-line-group] [data-ts-slg-actions] {
      opacity: 0;
      transition: opacity 150ms;
    }
    [data-ts-status-line-group]:hover [data-ts-slg-actions],
    [data-ts-status-line-group]:focus-within [data-ts-slg-actions] {
      opacity: 1;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureStatusLineGroupStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-status-line-gap)',
  fontFamily: 'var(--ts-status-line-font)',
  fontSize: 'var(--ts-status-line-font-size)',
  fontVariantNumeric: 'tabular-nums',
  lineHeight: 1.4,
  flexWrap: 'wrap',
  padding: '1px 0',
};

const colorDotStyle = (dotColor: string): CSSProperties => ({
  width: 8,
  height: 8,
  borderRadius: '50%',
  background: dotColor,
  flexShrink: 0,
});

const nameStyle: CSSProperties = {
  color: 'var(--ts-status-line-label-text)',
  userSelect: 'none',
  whiteSpace: 'nowrap',
};

const valueStyle: CSSProperties = {
  color: 'var(--ts-status-line-value-text)',
};

const dimmedContainerStyle: CSSProperties = {
  ...containerStyle,
  opacity: 0.5,
};

const actionsStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '2px',
  marginLeft: '2px',
};

export const StatusLineGroup = forwardRef<HTMLDivElement, StatusLineGroupProps>(
  function StatusLineGroup(
    {
      name,
      color,
      values,
      precision = 2,
      visible = true,
      onVisibilityToggle,
      onSettings,
      onRemove,
    },
    ref,
  ) {
    const hasActions = onVisibilityToggle !== undefined || onSettings !== undefined || onRemove !== undefined;
    const [hovered, setHovered] = useState(false);

    return (
      <div
        ref={ref}
        data-ts-status-line-group=""
        style={visible ? containerStyle : dimmedContainerStyle}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
      >
        {color !== undefined && <span style={colorDotStyle(color)} aria-hidden />}
        <span style={nameStyle}>{name}</span>
        {Object.entries(values).map(([key, val]) => (
          <span key={key} style={valueStyle}>
            {formatPrice(val, precision)}
          </span>
        ))}
        {hasActions && (
          <span data-ts-slg-actions="" style={actionsStyle}>
            {onVisibilityToggle !== undefined && (
              <IconButton
                icon={visible ? <Eye size={12} /> : <EyeOff size={12} />}
                label={visible ? `Hide ${name}` : `Show ${name}`}
                variant="ghost"
                size="sm"
                onClick={onVisibilityToggle}
              />
            )}
            {onSettings !== undefined && (
              <IconButton
                icon={<Settings size={12} />}
                label={`Settings for ${name}`}
                variant="ghost"
                size="sm"
                onClick={onSettings}
              />
            )}
            {onRemove !== undefined && (
              <IconButton
                icon={<Trash2 size={12} />}
                label={`Remove ${name}`}
                variant="ghost"
                size="sm"
                onClick={onRemove}
              />
            )}
          </span>
        )}
      </div>
    );
  },
);

StatusLineGroup.displayName = 'StatusLineGroup';
