/**
 * Hook for receiving cross-app drag-drop events in a target app.
 *
 * Listens for `deskmodal:dragEvent` postMessages from the DeskModal shell.
 * The shell sends `enter`, `leave`, and `drop` events as the cursor moves
 * across iframe boundaries during a cross-app drag.
 *
 * @example
 * ```tsx
 * const { isDragOver } = useDropTarget({
 *   accepts: ['fdc3.instrument'],
 *   onDrop: (context) => switchToInstrument(context),
 * });
 *
 * <div data-ts-drop-target style={{ outline: isDragOver ? '2px solid var(--ts-color-accent)' : 'none' }}>
 *   {children}
 * </div>
 * ```
 */

import { useCallback, useEffect, useRef, useState } from "react";
import type { Context } from "../fdc3-types";
import type {
  DragDropContext,
  DragEventMessage,
} from "../contexts/drag-drop-context";

export interface UseDropTargetOptions {
  /** FDC3 context types this target accepts (matched against innerContext.type). */
  accepts: string[];
  /** Called when a valid context is dropped on this app. */
  onDrop: (context: Context) => void;
  /** Called when a drag enters this app's tile. */
  onDragEnter?: (context: DragDropContext) => void;
  /** Called when a drag leaves this app's tile. */
  onDragLeave?: () => void;
}

export interface UseDropTargetResult {
  /** Whether a drag is currently hovering over this app. */
  isDragOver: boolean;
}

export function useDropTarget(options: UseDropTargetOptions): UseDropTargetResult {
  const [isDragOver, setIsDragOver] = useState(false);
  const optionsRef = useRef(options);
  optionsRef.current = options;

  // Notify the shell which context types this app accepts
  useEffect(() => {
    try {
      window.parent.postMessage(
        {
          type: "deskmodal:setDropCapability",
          payload: { accepts: optionsRef.current.accepts },
        },
        "*",
      );
    } catch {
      // Not in iframe or postMessage blocked
    }
  }, []);

  const handleMessage = useCallback((event: MessageEvent) => {
    // Only accept messages from the parent shell (same origin or the DeskModal shell).
    // In DeskModal, iframes share the same origin as the shell.
    if (event.source !== window.parent && event.source !== window) return;

    // Validate message structure: must be an object with the expected type field
    if (typeof event.data !== "object" || event.data === null) return;
    const data = event.data as DragEventMessage | undefined;
    if (!data || data.type !== "deskmodal:dragEvent") return;
    if (!data.payload || typeof data.payload !== "object") return;

    const { phase, context } = data.payload;
    if (!phase || !context) return;

    // Check if the inner context type is accepted
    const innerType = context?.innerContext?.type;
    if (innerType && !optionsRef.current.accepts.includes(innerType)) return;

    switch (phase) {
      case "enter":
        setIsDragOver(true);
        optionsRef.current.onDragEnter?.(context);
        break;
      case "leave":
      case "cancel":
        setIsDragOver(false);
        optionsRef.current.onDragLeave?.();
        break;
      case "drop":
        setIsDragOver(false);
        if (context?.innerContext) {
          optionsRef.current.onDrop(context.innerContext);
        }
        break;
    }
  }, []);

  useEffect(() => {
    window.addEventListener("message", handleMessage);
    return () => window.removeEventListener("message", handleMessage);
  }, [handleMessage]);

  return { isDragOver };
}
