import { forwardRef, useCallback, useRef, type CSSProperties, type KeyboardEvent } from 'react';
import { Search, Plus, Settings2, ArrowUp, ArrowDown, ArrowUpDown } from 'lucide-react';
import { Toolbar, IconButton, Tooltip } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  WatchlistHeader                                                            */
/*  Toolbar + sortable column headers for watchlist panel.                     */
/*  Uses --ts-data-header-* and --ts-toolbar-* tokens.                         */
/* -------------------------------------------------------------------------- */

export interface WatchlistColumn {
  /** Unique column identifier. */
  id: string;
  /** Display label for column header. */
  label: string;
  /** Column width in pixels or 'flex' for flexible width. */
  width: number | 'flex';
  /** Text alignment. */
  align?: 'left' | 'right';
  /** Minimum width in pixels (for resizable columns). */
  minWidth?: number;
}

/** View mode option for the segmented control. */
export interface ViewModeOption {
  /** Unique identifier for the view mode. */
  id: string;
  /** Short display label. */
  label: string;
}

export interface WatchlistHeaderProps {
  /** Column definitions determining visible columns and their order. */
  columns: WatchlistColumn[];
  /** Current sort column ID, or null if unsorted. */
  sortColumn: string | null;
  /** Sort direction. */
  sortDirection: 'asc' | 'desc';
  /** Called when a column header is clicked for sorting. */
  onSort: (columnId: string) => void;
  /** Called when the search button is clicked. */
  onSearchClick: () => void;
  /** Called when the column config button is clicked. */
  onColumnConfigClick: () => void;
  /** Called when the add symbol button is clicked. */
  onAddSymbolClick: () => void;
  /** Called when a column is resized by dragging. */
  onColumnResize?: (columnId: string, newWidth: number) => void;
  /** Currently active view mode ID. */
  viewMode?: string;
  /** Called when the user switches view mode. */
  onViewModeChange?: (mode: string) => void;
  /** Available view modes for the segmented control. */
  viewModes?: ViewModeOption[];
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-watchlist-header-styles';

function ensureWatchlistHeaderStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-watchlist-header-col]:hover {
      color: var(--ts-text-primary);
      cursor: pointer;
    }
    [data-ts-watchlist-header-col]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-col-resize-handle] {
      width: 12px;
      margin: 0 -6px;
      cursor: col-resize;
      flex-shrink: 0;
      align-self: stretch;
      position: relative;
      z-index: 3;
      touch-action: none;
    }
    [data-ts-col-resize-handle]::after {
      content: '';
      position: absolute;
      top: 4px;
      bottom: 4px;
      left: 50%;
      transform: translateX(-50%);
      width: 1px;
      background: var(--ts-panel-border, #2e2e3e);
      transition: width 0.1s, background 0.1s;
    }
    [data-ts-col-resize-handle]:hover::after,
    [data-ts-col-resize-handle][data-dragging]::after {
      width: 3px;
      background: var(--ts-accent-default, #3b82f6);
      border-radius: 1px;
    }
    [data-ts-view-mode-group] {
      display: inline-flex;
      border-radius: var(--ts-radius-sm, 4px);
      overflow: hidden;
      border: 1px solid var(--ts-panel-border, #2e2e3e);
    }
    [data-ts-view-mode-btn] {
      height: 24px;
      padding: 0 8px;
      font-size: var(--ts-font-xs, 11px);
      font-weight: 500;
      font-family: inherit;
      border: none;
      cursor: pointer;
      background: transparent;
      color: var(--ts-text-secondary, #9ca3af);
      transition: background 100ms, color 100ms;
      white-space: nowrap;
    }
    [data-ts-view-mode-btn]:hover {
      background: var(--ts-surface-secondary, #1e1e2e);
      color: var(--ts-text-primary, #e5e7eb);
    }
    [data-ts-view-mode-btn][data-active] {
      background: var(--ts-accent-default, #3b82f6);
      color: var(--ts-text-on-accent, #ffffff);
    }
    [data-ts-view-mode-btn]:focus-visible {
      outline: 2px solid var(--ts-accent-default, #3b82f6);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureWatchlistHeaderStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const titleStyle: CSSProperties = {
  flex: 1,
  fontSize: 'var(--ts-font-md)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-text-primary)',
  whiteSpace: 'nowrap',
};

const columnRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-data-header-height)',
  padding: '0 var(--ts-data-header-padding-x)',
  background: 'var(--ts-data-header-bg)',
  borderBottom: '1px solid var(--ts-data-header-border)',
};

const columnHeaderBaseStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: '2px',
  fontSize: 'var(--ts-data-header-font-size)',
  fontWeight: 'var(--ts-data-header-font-weight)' as unknown as number,
  color: 'var(--ts-data-header-text)',
  textTransform: 'uppercase',
  userSelect: 'none',
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  border: 'none',
  background: 'none',
  padding: 0,
  fontFamily: 'inherit',
  cursor: 'pointer',
  boxSizing: 'border-box',
};

/* ----- Helpers ----------------------------------------------------------- */

function getSortIcon(
  columnId: string,
  sortColumn: string | null,
  sortDirection: 'asc' | 'desc',
): React.JSX.Element {
  if (sortColumn !== columnId) {
    return <ArrowUpDown size={12} style={{ color: 'var(--ts-data-header-sort-icon)' }} />;
  }
  const iconColor = 'var(--ts-data-header-sort-icon-active)';
  return sortDirection === 'asc'
    ? <ArrowUp size={12} style={{ color: iconColor }} />
    : <ArrowDown size={12} style={{ color: iconColor }} />;
}

function getAriaSortValue(
  columnId: string,
  sortColumn: string | null,
  sortDirection: 'asc' | 'desc',
): 'ascending' | 'descending' | 'none' {
  if (sortColumn !== columnId) return 'none';
  return sortDirection === 'asc' ? 'ascending' : 'descending';
}

/* ----- Component --------------------------------------------------------- */

export const WatchlistHeader = forwardRef<HTMLDivElement, WatchlistHeaderProps>(function WatchlistHeader({
  columns,
  sortColumn,
  sortDirection,
  onSort,
  onSearchClick,
  onColumnConfigClick,
  onAddSymbolClick,
  onColumnResize,
  viewMode,
  onViewModeChange,
  viewModes,
}, ref) {
  const handleColumnKeyDown = useCallback(
    (event: KeyboardEvent<HTMLButtonElement>, columnId: string) => {
      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        onSort(columnId);
      }
    },
    [onSort],
  );

  // Column resize drag handling
  const dragState = useRef<{ columnId: string; startX: number; startWidth: number } | null>(null);

  const handleResizeMouseDown = useCallback(
    (e: React.MouseEvent, colId: string, currentWidth: number) => {
      e.preventDefault();
      e.stopPropagation();
      // Look up the column's minWidth for clamping during drag
      const col = columns.find((c) => c.id === colId);
      const minW = col?.minWidth ?? 40;
      dragState.current = { columnId: colId, startX: e.clientX, startWidth: currentWidth };
      const handle = e.currentTarget as HTMLElement;
      handle.dataset.dragging = '';
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';
      document.body.dataset.splitterDragging = 'true';

      function onMove(ev: MouseEvent) {
        if (!dragState.current) return;
        const delta = ev.clientX - dragState.current.startX;
        const newWidth = Math.max(minW, dragState.current.startWidth + delta);
        onColumnResize?.(dragState.current.columnId, newWidth);
      }

      function onUp() {
        if (handle) delete handle.dataset.dragging;
        dragState.current = null;
        document.body.style.cursor = '';
        document.body.style.userSelect = '';
        delete document.body.dataset.splitterDragging;
        window.removeEventListener('mousemove', onMove);
        window.removeEventListener('mouseup', onUp);
      }

      window.addEventListener('mousemove', onMove);
      window.addEventListener('mouseup', onUp);
    },
    [onColumnResize],
  );

  return (
    <div ref={ref} data-ts-watchlist-header="" data-testid="watchlist-header">
      <Toolbar>
        <span style={titleStyle}>Watchlist</span>
        <Tooltip content="Search symbols">
          <IconButton
            icon={<Search size={14} />}
            label="Search symbols"
            variant="ghost"
            size="sm"
            onClick={onSearchClick}
            data-testid="watchlist-search-btn"
          />
        </Tooltip>
        <Tooltip content="Add symbol">
          <IconButton
            icon={<Plus size={14} />}
            label="Add symbol"
            variant="ghost"
            size="sm"
            onClick={onAddSymbolClick}
            data-testid="watchlist-add-btn"
          />
        </Tooltip>
        {viewModes && viewModes.length > 0 && onViewModeChange && (
          <div data-ts-view-mode-group="" role="group" aria-label="View mode" data-testid="watchlist-view-mode-group">
            {viewModes.map((mode) => (
              <button
                key={mode.id}
                type="button"
                data-ts-view-mode-btn=""
                {...(viewMode === mode.id ? { 'data-active': '' } : {})}
                aria-pressed={viewMode === mode.id}
                onClick={() => onViewModeChange(mode.id)}
                data-testid={`watchlist-view-mode-${mode.id}`}
              >
                {mode.label}
              </button>
            ))}
          </div>
        )}
        <Tooltip content="Configure columns">
          <IconButton
            icon={<Settings2 size={14} />}
            label="Configure columns"
            variant="ghost"
            size="sm"
            onClick={onColumnConfigClick}
            data-testid="watchlist-config-btn"
          />
        </Tooltip>
      </Toolbar>
      <div style={columnRowStyle} role="row" data-testid="watchlist-column-headers">
        {columns.map((col, i) => {
          const colWidth = typeof col.width === 'number' ? col.width : undefined;
          const isFlex = col.width === 'flex';
          const minW = col.minWidth ?? 40;
          const effectiveWidth = colWidth ? Math.max(colWidth, minW) : undefined;
          const colStyle: CSSProperties = {
            ...columnHeaderBaseStyle,
            width: `${effectiveWidth ?? minW}px`,
            minWidth: `${minW}px`,
            flexShrink: 0,
            justifyContent: col.align === 'right' ? 'flex-end' : 'flex-start',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
          };
          // Render column button + resize handle as separate fragments
          // (no wrapper div that could break flex layout)
          const resizeHandle = onColumnResize ? (
            <div
              key={`resize-${col.id}`}
              data-ts-col-resize-handle=""
              data-resize-col={col.id}
              onMouseDown={(e) => {
                // Measure the actual rendered width of the column button
                const colBtn = e.currentTarget.previousElementSibling as HTMLElement | null;
                const measuredWidth = colBtn ? colBtn.getBoundingClientRect().width : (colWidth ?? 100);
                handleResizeMouseDown(e, col.id, measuredWidth);
              }}
              title={`Drag to resize ${col.label}`}
              role="separator"
              aria-orientation="vertical"
              aria-label={`Resize ${col.label} column`}
              tabIndex={-1}
            />
          ) : null;

          return [
            <button
              key={col.id}
              type="button"
              data-ts-watchlist-header-col=""
              data-col-id={col.id}
              style={colStyle}
              aria-sort={getAriaSortValue(col.id, sortColumn, sortDirection)}
              onClick={() => onSort(col.id)}
              onKeyDown={(e) => handleColumnKeyDown(e, col.id)}
              data-testid={`watchlist-col-${col.id}`}
            >
              <span>{col.label}</span>
              {getSortIcon(col.id, sortColumn, sortDirection)}
            </button>,
            resizeHandle,
          ];
        })}
      </div>
    </div>
  );
});
